provider "aws" {
  alias  = "main"
  region = "us-west-1"
}

provider "aws" {
  alias  = "us-east"
  region = "us-east-1"
}

provider "aws" {
  alias  = "eu-central"
  region = "eu-central-1"
}

provider "aws" {
  alias  = "ap-southeast"
  region = "ap-southeast-1"
}

# Random resources for unique identifiers and passwords
resource "random_id" "suffix" {
  byte_length = 4
}

resource "random_password" "db_primary" {
  length  = 16
  special = false
}

resource "random_password" "db_replica_us_east" {
  length  = 16
  special = false
}

resource "random_password" "db_replica_eu_central" {
  length  = 16
  special = false
}

