  length  = 16
  special = false
}

# Primary DB Instance in us-west-1
resource "aws_db_instance" "primary" {
  provider = aws.main

  identifier          = "primary-${random_id.suffix.hex}"
  allocated_storage   = 20
  engine              = "mysql"
  instance_class      = "db.t3.micro"
  db_name             = "primarydb"
  username            = "admin"
  password            = random_password.db_primary.result
  skip_final_snapshot = true

  publicly_accessible = true
}

# Replica in us-east-1
resource "aws_db_instance" "replica_us_east" {
  provider = aws.us-east

  identifier          = "replica-us-east-${random_id.suffix.hex}"
  allocated_storage   = 20
  engine              = "mysql"
  instance_class      = "db.t3.micro"
  db_name             = "replicadb"
  username            = "admin"
