provider "aws" {
  alias  = "us_west_2"
  region = "us-west-2"
}

provider "aws" {
  alias  = "eu_central_1"
  region = "eu-central-1"
}

provider "aws" {
  alias  = "us_east_1"
  region = "us-east-1"
}

# IAM Role for Elastic Beanstalk (shared across regions)
resource "aws_iam_role" "eb_service" {
  provider = aws.us_east_1
  name     = "aws-elasticbeanstalk-service-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = {
        Service = "elasticbeanstalk.amazonaws.com"
      }
    }]
  })
}

resource "aws_iam_role_policy_attachment" "eb_service" {
  provider   = aws.us_east_1
  role       = aws_iam_role.eb_service.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSElasticBeanstalkService"
}

resource "aws_iam_role" "eb_ec2" {
  provider = aws.us_east_1
  name     = "aws-elasticbeanstalk-ec2-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = {
        Service = "ec2.amazonaws.com"
      }
    }]
  })
}

resource "aws_iam_role_policy_attachment" "eb_ec2" {
  provider   = aws.us_east_1
  role       = aws_iam_role.eb_ec2.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}

resource "aws_iam_instance_profile" "eb_ec2" {
  provider = aws.us_east_1
  name     = "aws-elasticbeanstalk-ec2-profile"
  role     = aws_iam_role.eb_ec2.name
}

# S3 bucket for application versions (created in us-east-1, used by both)
resource "aws_s3_bucket" "app_bucket" {
  provider = aws.us_east_1
  bucket   = "elasticbeanstalk-app-versions-${random_id.suffix.hex}"
}

resource "aws_s3_bucket_versioning" "app_bucket" {
  provider = aws.us_east_1
  bucket   = aws_s3_bucket.app_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "random_id" "suffix" {
  byte_length = 4
}

# Application version
resource "aws_s3_object" "app_version" {
  provider     = aws.us_east_1
  bucket       = aws_s3_bucket.app_bucket.id
  key          = "app.zip"
  source       = "${path.module}/app.zip"
  content_type = "application/zip"
}

resource "aws_elastic_beanstalk_application" "app" {
  provider   = aws.us_east_1
  name       = "multi-region-app"
  depends_on = [aws_s3_object.app_version]
}

resource "aws_elastic_beanstalk_application_version" "app_version" {
  provider    = aws.us_east_1
  name        = "v1"
  application = aws_elastic_beanstalk_application.app.name
  bucket      = aws_s3_bucket.app_bucket.id
  key         = aws_s3_object.app_version.id
}

# US West environment
resource "aws_elastic_beanstalk_environment" "us_west" {
  provider            = aws.us_west_2
  name                = "us_west"
  application         = aws_elastic_beanstalk_application.app.name
  solution_stack_name = "64bit Amazon Linux 2 v3.4.1 running Python 3.8"
  version_label       = aws_elastic_beanstalk_application_version.app_version.name

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2.name
  }

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "InstanceType"
    value     = "t3.micro"
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "ServiceRole"
    value     = aws_iam_role.eb_service.name
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "EnvironmentType"
    value     = "SingleInstance"
  }
}

# EU Central environment
resource "aws_elastic_beanstalk_environment" "eu_central" {
  provider            = aws.eu_central_1
  name                = "eu_central"
  application         = aws_elastic_beanstalk_application.app.name
  solution_stack_name = "64bit Amazon Linux 2 v3.4.1 running Python 3.8"
  version_label       = aws_elastic_beanstalk_application_version.app_version.name

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2.name
  }

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "InstanceType"
    value     = "t3.micro"
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "ServiceRole"
    value     = aws_iam_role.eb_service.name
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "EnvironmentType"
    value     = "SingleInstance"
  }
}

# Route 53 hosted zone (must be in us-east-1 for CloudFront, but using for latency routing)
resource "aws_route53_zone" "main" {
  provider = aws.us_east_1
  name     = "example.com"
}

# Health check for US West
resource "aws_route53_health_check" "us_west" {
  provider          = aws.us_east_1
  fqdn              = aws_elastic_beanstalk_environment.us_west.cname
  port              = 80
  type              = "HTTP"
  resource_path     = "/"
  failure_threshold = 3
  request_interval  = 30

  tags = {
    Name = "us-west-health-check"
  }
}

# Health check for EU Central
resource "aws_route53_health_check" "eu_central" {
  provider          = aws.us_east_1
  fqdn              = aws_elastic_beanstalk_environment.eu_central.cname
  port              = 80
  type              = "HTTP"
  resource_path     = "/"
  failure_threshold = 3
  request_interval  = 30

  tags = {
    Name = "eu-central-health-check"
  }
}

# Geolocation record for North America -> US West
resource "aws_route53_record" "us_west_geo" {
  provider = aws.us_east_1
  zone_id  = aws_route53_zone.main.zone_id
  name     = "app.example.com"
  type     = "CNAME"
  ttl      = 60

  geolocation_routing_policy {
    continent = "NA"
  }

  set_identifier = "us-west"
  health_check_id = aws_route53_health_check.us_west.id
  records        = [aws_elastic_beanstalk_environment.us_west.cname]
}

# Geolocation record for South America -> US West
resource "aws_route53_record" "us_west_geo_sa" {
  provider = aws.us_east_1
  zone_id  = aws_route53_zone.main.zone_id
  name     = "app.example.com"
  type     = "CNAME"
  ttl      = 60

  geolocation_routing_policy {
    continent = "SA"
  }

  set_identifier = "us-west-sa"
  health_check_id = aws_route53_health_check.us_west.id
  records        = [aws_elastic_beanstalk_environment.us_west.cname]
}

# Geolocation record for Europe -> EU Central
resource "aws_route53_record" "eu_central_geo" {
  provider = aws.us_east_1
  zone_id  = aws_route53_zone.main.zone_id
  name     = "app.example.com"
  type     = "CNAME"
  ttl      = 60

  geolocation_routing_policy {
    continent = "EU"
  }

  set_identifier = "eu-central"
  health_check_id = aws_route53_health_check.eu_central.id
  records        = [aws_elastic_beanstalk_environment.eu_central.cname]
}

# Geolocation record for Asia -> EU Central (closest)
resource "aws_route53_record" "eu_central_geo_asia" {
  provider = aws.us_east_1
  zone_id  = aws_route53_zone.main.zone_id
  name     = "app.example.com"
  type     = "CNAME"
  ttl      = 60

  geolocation_routing_policy {
    continent = "AS"
  }

  set_identifier = "eu-central-asia"
  health_check_id = aws_route53_health_check.eu_central.id
  records        = [aws_elastic_beanstalk_environment.eu_central.cname]
}

# Geolocation record for Oceania -> US West (closest)
resource "aws_route53_record" "us_west_geo_oceania" {
  provider = aws.us_east_1
  zone_id  = aws_route53_zone.main.zone_id
  name     = "app.example.com"
  type     = "CNAME"
  ttl      = 60

  geolocation_routing_policy {
    continent = "OC"
  }

  set_identifier = "us-west-oceania"
  health_check_id = aws_route53_health_check.us_west.id
  records        = [aws_elastic_beanstalk_environment.us_west.cname]
}

# Geolocation record for Africa -> EU Central (closest)
resource "aws_route53_record" "eu_central_geo_africa" {
  provider = aws.us_east_1
  zone_id  = aws_route53_zone.main.zone_id
  name     = "app.example.com"
  type     = "CNAME"
  ttl      = 60

  geolocation_routing_policy {
    continent = "AF"
  }

  set_identifier = "eu-central-africa"
  health_check_id = aws_route53_health_check.eu_central.id
  records        = [aws_elastic_beanstalk_environment.eu_central.cname]
}

# Default geolocation record (US West as fallback)
resource "aws_route53_record" "default_geo" {
  provider = aws.us_east_1
  zone_id  = aws_route53_zone.main.zone_id
  name     = "app.example.com"
  type     = "CNAME"
  ttl      = 60

  geolocation_routing_policy {
    country = "*"
  }

  set_identifier = "default"
  health_check_id = aws_route53_health_check.us_west.id
  records        = [aws_elastic_beanstalk_environment.us_west.cname]
}

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"

      configuration_aliases = [ aws.default, aws.west, aws.europe ]
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region = "us-east-1" # Default region
  alias  = "default"

  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

provider "aws" {
  region = "us-west-1"
  alias  = "west"

  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

provider "aws" {
  region = "eu-central-1"
  alias  = "europe"

  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_iam_role" "eb_ec2_role" {
  provider = aws.default
  name = "elastic_beanstalk_ec2_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Effect = "Allow",
        Principal = {
          Service = "ec2.amazonaws.com"
        },
      },
    ]
  })
}

# Attach the AWS managed policy for Elastic Beanstalk to the role
resource "aws_iam_role_policy_attachment" "eb_managed_policy" {
  provider = aws.default
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}

# Create an instance profile tied to the role
resource "aws_iam_instance_profile" "eb_ec2_profile" {
  provider = aws.default
  name = "elastic_beanstalk_ec2_profile"
  role = aws_iam_role.eb_ec2_role.name
}

resource "aws_s3_bucket" "us_west_sample_bucket" {
  provider = aws.west
  bucket_prefix = "sample-"
}

resource "aws_s3_object" "us_west_examplebucket_object" {
  provider = aws.west
  key    = "app"
  bucket = aws_s3_bucket.us_west_sample_bucket.id
  source = "./supplement/app.zip"
}

# Elastic Beanstalk application
resource "aws_elastic_beanstalk_application" "us_west" {
  provider = aws.west
  name        = "my-global-app"
  description = "A global application deployed in US-West."
}

resource "aws_elastic_beanstalk_application_version" "us_west_version" {
  provider = aws.west
  name        = "v1"
  application = aws_elastic_beanstalk_application.us_west.name
  bucket = aws_s3_object.us_west_examplebucket_object.bucket
  key    = aws_s3_object.us_west_examplebucket_object.key
}

# US-West Elastic Beanstalk Environment
resource "aws_elastic_beanstalk_environment" "us_west" {
  provider            = aws.west
  name                = "my-global-app-us-west"
  application         = aws_elastic_beanstalk_application.us_west.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.3.0 running Python 3.9"

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile.name
  }
}

resource "aws_s3_bucket" "eu_sample_bucket" {
  provider = aws.europe
  bucket_prefix = "sample-"
}

resource "aws_s3_object" "eu_examplebucket_object" {
  provider = aws.europe
  key    = "app"
  bucket = aws_s3_bucket.eu_sample_bucket.id
  source = "./supplement/app.zip"
}

# Elastic Beanstalk Application (EU-Central Region)
resource "aws_elastic_beanstalk_application" "eu_central" {
  provider = aws.europe
  name        = "my-global-app"
  description = "A global application deployed in EU-Central."
}

resource "aws_elastic_beanstalk_application_version" "europe_version" {
  provider = aws.europe
  name        = "v1"
  application = aws_elastic_beanstalk_application.eu_central.name
  bucket = aws_s3_object.eu_examplebucket_object.bucket
  key    = aws_s3_object.eu_examplebucket_object.key
}

# EU-Central Elastic Beanstalk Environment
resource "aws_elastic_beanstalk_environment" "eu_central" {
  provider            = aws.europe
  name                = "my-global-app-eu-central"
  application         = aws_elastic_beanstalk_application.eu_central.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.3.0 running Python 3.9"

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile.name
  }
}

# Route53 Hosted Zone for the domain
resource "aws_route53_zone" "main" {
  provider = aws.default
  name     = "myglobalapp.com"
}

# Geolocation Routing Policy Records for Route 53 to direct traffic based on location
resource "aws_route53_record" "us_west" {
  provider    = aws.default
  zone_id     = aws_route53_zone.main.zone_id
  name        = "west.myglobalapp.com"
  type        = "CNAME"
  ttl         = "60"
  set_identifier = "us-west"
  geolocation_routing_policy {
    continent = "NA"
  }
  records = [
    aws_elastic_beanstalk_environment.us_west.name
  ]
}

resource "aws_route53_record" "eu_central" {
  provider    = aws.default
  zone_id     = aws_route53_zone.main.zone_id
  name        = "central.myglobalapp.com"
  type        = "CNAME"
  ttl         = "60"
  set_identifier = "eu-central"
  geolocation_routing_policy {
    continent = "EU"
  }
  records = [
    aws_elastic_beanstalk_environment.eu_central.name
  ]
}

