  provider          = aws.us-east-1
  fqdn              = aws_elastic_beanstalk_environment.us_east.cname
  port              = 80
  type              = "HTTP"
  resource_path     = "/"
  failure_threshold = 3
  request_interval  = 30

  tags = {
    Name = "health-check-us-east"
  }
}

