resource "aws_codebuild_project" "example" {
  name          = "sample-project"
  description   = "Sample CodeBuild project with multiple sources and artifacts"
  build_timeout = "60"
  service_role  = aws_iam_role.codebuild.arn

  artifacts {
    type = "S3"
    location = "my-bucket"
    name     = "primary-artifacts"
    path     = "build-output/"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:5.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"
    privileged_mode             = true

    environment_variable {
      name  = "ENVIRONMENT"
      value = "production"
    }

    environment_variable {
      name  = "API_KEY"
      value = "example-api-key"
      type  = "PLAINTEXT"
    }

    environment_variable {
      name  = "SECRET_TOKEN"
      value = "arn:aws:secretsmanager:us-east-1:123456789012:secret:my-secret"
      type  = "SECRETS_MANAGER"
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/example/main-repo.git"
    git_clone_depth = 1
    buildspec       = "buildspec.yml"
  }

  secondary_sources {
    type              = "GITHUB"
    location          = "https://github.com/example/shared-library.git"
    source_identifier = "shared_lib"
    git_clone_depth   = 1
  }

  secondary_sources {
    type              = "GITHUB"
    location          = "https://github.com/example/configs.git"
    source_identifier = "config_repo"
    git_clone_depth   = 1
  }

  secondary_artifacts {
    type                = "S3"
    location            = "my-bucket"
    name                = "secondary-artifacts-1"
    path                = "secondary-output-1/"
    artifact_identifier = "artifact1"
  }

  secondary_artifacts {
    type                = "S3"
    location            = "my-bucket"
    name                = "secondary-artifacts-2"
    path                = "secondary-output-2/"
    artifact_identifier = "artifact2"
  }

  cache {
    type  = "S3"
    location = "my-bucket/cache"
  }

  tags = {
    Environment = "production"
    Project     = "sample"
  }
}

