resource "aws_lex_intent" "order_pizza" {
  name = "OrderPizzaIntent"

  sample_utterances = [
    "I want to order a pizza",
    "Order a pizza",
    "I'd like a pizza",
    "Pizza please",
    "I want pizza"
  ]

  confirmation_prompt {
    max_attempts = 2
    message {
      content      = "Great! I've got your order for a {PizzaSize} {PizzaType} pizza with {Toppings}. Should I go ahead and place this order?"
      content_type = "PlainText"
    }
  }

  rejection_statement {
    message {
      content      = "Okay, I've cancelled your pizza order. Let me know if you'd like to order something else."
      content_type = "PlainText"
    }
  }

  follow_up_prompt {
    prompt {
      max_attempts = 2
      message {
        content      = "Would you like to order another pizza or is there anything else I can help you with?"
        content_type = "PlainText"
      }
    }
    rejection_statement {
      message {
        content      = "Thanks for using our pizza ordering service. Have a great day!"
        content_type = "PlainText"
      }
    }
  }

  slot {
    name           = "PizzaType"
    slot_type      = "PizzaTypeValues"
    slot_type_version = "$LATEST"
    priority       = 1
    description    = "The type of pizza to order"

    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "What type of pizza would you like? We have cheese, pepperoni, or vegetarian."
        content_type = "PlainText"
      }
    }
  }

  slot {
    name           = "PizzaSize"
    slot_type      = "PizzaSizeValues"
    slot_type_version = "$LATEST"
    priority       = 2
    description    = "The size of the pizza"

    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "What size pizza would you like? Small, medium, or large?"
        content_type = "PlainText"
      }
    }
  }

  slot {
    name           = "Toppings"
    slot_type      = "AMAZON.LITERAL"
    priority       = 3
    description    = "Additional toppings for the pizza"

    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "What toppings would you like on your pizza?"
        content_type = "PlainText"
      }
    }
  }

  fulfillment_activity {
    type = "ReturnIntent"
  }
}

