    "I want to book a car",
    "Book a car rental",
    "I need a car for my trip",
    "Rent a car",
    "Book me a car"
  ]

  fulfillment_activity {
    type = "ReturnIntent"
  }

  slot {
    name = "PickUpCity"
    description = "The city where the customer wants to pick up the car"
    slot_constraint = "Required"
    slot_type = "AMAZON.US_CITY"
    priority = 1

    value_elicitation_prompt {
      max_attempts = 3
      message {
        content_type = "PlainText"
        content      = "In which city do you want to pick up the car?"
      }
    }
  }

  slot {
    name = "PickUpDate"
    description = "The date when the customer wants to pick up the car"
    slot_constraint = "Required"
    slot_type = "AMAZON.DATE"
    priority = 2

    value_elicitation_prompt {
      max_attempts = 3
      message {
        content_type = "PlainText"
        content      = "What date do you want to pick up the car?"
      }
    }
  }

  slot {
    name = "ReturnDate"
    description = "The date when the customer wants to return the car"
    slot_constraint = "Required"
    slot_type = "AMAZON.DATE"
    priority = 3

    value_elicitation_prompt {
      max_attempts = 3
      message {
        content_type = "PlainText"
        content      = "What date will you return the car?"
      }
    }
  }

  slot {
    name = "DriverAge"
    description = "The age of the driver"
    slot_constraint = "Required"
    slot_type = "AMAZON.NUMBER"
    priority = 4

    value_elicitation_prompt {
      max_attempts = 3
      message {
        content_type = "PlainText"
        content      = "How old is the driver?"
      }
    }
  }

  slot {
