    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "What is your order number?"
        content_type = "PlainText"
      }
    }
  }
}

resource "aws_lex_intent" "cancel_order" {
  name = "CancelOrder-${random_id.suffix.hex}"
  description = "Intent to cancel an existing order"

  sample_utterances = [
    "Cancel my order",
    "I want to cancel",
    "Please cancel my pizza",
    "I need to cancel my order"
  ]

  fulfillment_activity {
    type = "ReturnIntent"
  }

  slot {
    name           = "OrderNumber"
    slot_constraint = "Required"
    slot_type      = "AMAZON.NUMBER"
    priority       = 1

    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "What is your order number?"
        content_type = "PlainText"
      }
    }
  }

  confirmation_prompt {
    max_attempts = 2
    message {
      content      = "Are you sure you want to cancel order number {OrderNumber}?"
      content_type = "PlainText"
    }
  }

  rejection_statement {
    message {
      content      = "Your order will not be cancelled."
      content_type = "PlainText"
    }
  }
}

resource "aws_lex_intent" "modify_order" {
  name = "ModifyOrder-${random_id.suffix.hex}"
  description = "Intent to modify an existing order"

  sample_utterances = [
    "I want to change my order",
    "Can I modify my pizza",
    "I need to update my order",
    "Change my toppings"
  ]

  fulfillment_activity {
    type = "ReturnIntent"
  }

  slot {
    name           = "OrderNumber"
    slot_constraint = "Required"
    slot_type      = "AMAZON.NUMBER"
    priority       = 1

    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "What is your order number?"
        content_type = "PlainText"
      }
    }
  }

  slot {
    name           = "Modification"
    slot_constraint = "Required"
    slot_type      = "ModificationType"
    slot_type_version = "$$LATEST"
    priority       = 2

    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "What would you like to modify? Size, crust, or toppings?"
        content_type = "PlainText"
      }
    }
  }
}

