    "Yummy pizza time",
    "I'm hungry for pizza"
  ]

  slot {
    name           = "PizzaType"
    description    = "The type of pizza the child wants"
    slot_constraint = "Required"
    slot_type      = "PizzaTypeValues"
    value_elicitation_prompt {
      max_attempts = 2
      message {
        content_type = "PlainText"
        content      = "What kind of pizza would you like? We have cheese, pepperoni, or veggie!"
      }
    }
  }

  slot {
    name           = "PizzaSize"
    description    = "The size of the pizza"
    slot_constraint = "Required"
    slot_type      = "PizzaSizeValues"
    value_elicitation_prompt {
      max_attempts = 2
      message {
        content_type = "PlainText"
        content      = "What size pizza? Small, medium, or large?"
      }
    }
  }

  slot {
    name           = "Toppings"
    description    = "Extra toppings for the pizza"
    slot_constraint = "Optional"
    slot_type      = "ToppingsValues"
    value_elicitation_prompt {
      max_attempts = 2
      message {
        content_type = "PlainText"
        content      = "Would you like any extra toppings? You can say mushrooms, olives, or none!"
      }
    }
  }

  confirmation_prompt {
    max_attempts = 2
    message {
      content_type = "PlainText"
      content      = "Okay, so you want a {PizzaSize} {PizzaType} pizza {Toppings}. Is that right?"
    }
  }

  rejection_statement {
    message {
      content_type = "PlainText"
      content      = "No problem! Let's try again. What would you like?"
    }
  }

  fulfillment_activity {
    type = "ReturnIntent"
  }
}

