  source {
    content  = <<EOF
exports.handler = async (event) => {
    console.log('Pizza order received:', JSON.stringify(event, null, 2));

    const size = event.currentIntent.slots.Size;
    const crust = event.currentIntent.slots.Crust;
    const toppings = event.currentIntent.slots.Toppings;

    const response = {
        dialogAction: {
            type: 'Close',
            fulfillmentState: 'Fulfilled',
            message: {
                contentType: 'PlainText',
                content: `Your ${size} ${crust} pizza with ${toppings} has been ordered! It will be ready in 30 minutes.`
            }
        }
    };

    return response;
};
EOF
    filename = "index.js"
  }
}

