  name                   = "example-kinesis-analytics-app"
  runtime_environment    = "FLINK-1_15"
  service_execution_role = aws_iam_role.kinesis_analytics.arn

  application_configuration {
    application_code_configuration {
      code_content {
        s3_content_location {
          bucket_arn     = aws_s3_bucket.example.arn
          file_key       = aws_s3_object.example.key
        }
      }
      code_content_type = "ZIPFILE"
    }

    environment_properties {
      property_group {
        property_group_id = "ConsumerConfigProperties"
        property_map = {
          "aws.region"       = "us-east-1"
          "input.stream.name" = aws_kinesis_stream.input.name
        }
      }
    }
  }
}

resource "aws_iam_role" "kinesis_analytics" {
  name = "kinesis-analytics-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kinesisanalytics.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "kinesis_analytics" {
  name = "kinesis-analytics-policy"
  role = aws_iam_role.kinesis_analytics.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "kinesis:DescribeStream",
          "kinesis:GetShardIterator",
          "kinesis:GetRecords",
          "kinesis:ListShards"
        ]
        Resource = aws_kinesis_stream.input.arn
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:GetObjectVersion"
        ]
        Resource = "${aws_s3_bucket.example.arn}/*"
      }
    ]
  })
}

