resource "aws_kinesisanalyticsv2_application" "example" {
  name                   = "example-flink-application"
  description            = "Apache Flink application managed by Kinesis Data Analytics V2"
  runtime_environment    = "FLINK-1_18"
  service_execution_role = aws_iam_role.kinesis_analytics.arn

  application_configuration {
    application_code_configuration {
      code_content {
        s3_content_location {
          bucket_arn     = aws_s3_bucket.example.arn
          file_key       = aws_s3_object.flink_jar.key
          object_version = aws_s3_object.flink_jar.version_id
        }
      }

      code_content_type = "ZIPFILE"
    }

    environment_properties {
      property_group {
        property_group_id = "FlinkApplicationProperties"

        property_map = {
          "InputStreamName" = aws_kinesis_stream.input.name
          "OutputStreamName" = aws_kinesis_stream.output.name
        }
      }
    }

    flink_application_configuration {
      checkpoint_configuration {
        configuration_type = "DEFAULT"
      }

      monitoring_configuration {
        configuration_type = "CUSTOM"
        log_level          = "INFO"
        metrics_level      = "APPLICATION"
      }

      parallelism_configuration {
        auto_scaling_enabled = true
        configuration_type   = "CUSTOM"
        parallelism          = 2
        parallelism_per_kpu  = 1
      }
    }
  }
}

resource "aws_iam_role" "kinesis_analytics" {
  name = "kinesis-analytics-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
