    application_code_configuration {
      code_content {
        s3_content_location {
          bucket_arn     = aws_s3_bucket.example.arn
          file_key       = aws_s3_object.flink_jar.key
          object_version = aws_s3_object.flink_jar.version_id
        }
      }

      code_content_type = "ZIPFILE"
    }

    environment_properties {
      property_group {
        property_group_id = "FlinkApplicationProperties"

        property_map = {
          "InputStreamName" = aws_kinesis_stream.input.name
          "OutputStreamName" = aws_kinesis_stream.output.name
        }
      }
    }

    flink_application_configuration {
      checkpoint_configuration {
        configuration_type = "DEFAULT"
      }

      monitoring_configuration {
        configuration_type = "CUSTOM"
        log_level          = "INFO"
        metrics_level      = "APPLICATION"
      }

      parallelism_configuration {
        auto_scaling_enabled = true
        configuration_type   = "CUSTOM"
        parallelism          = 2
        parallelism_per_kpu  = 1
      }
    }
  }
}

resource "aws_iam_role" "kinesis_analytics" {
  name = "kinesis-analytics-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kinesisanalytics.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "kinesis_analytics" {
  name = "kinesis-analytics-policy"
  role = aws_iam_role.kinesis_analytics.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "kinesis:DescribeStream",
          "kinesis:GetShardIterator",
          "kinesis:GetRecords",
          "kinesis:ListShards",
          "kinesis:PutRecord",
          "kinesis:PutRecords"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:GetObjectVersion"
        ]
        Resource = "${aws_s3_bucket.example.arn}/*"
      },
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "*"
      }
    ]
  })
}

resource "aws_s3_bucket" "example" {
  bucket_prefix = "kinesis-analytics-"
}

resource "aws_s3_object" "flink_jar" {
  bucket = aws_s3_bucket.example.id
  key    = "flink-application.jar"
  source = "flink-application.jar"

  # In practice, upload your Flink JAR to S3
}

resource "aws_kinesis_stream" "input" {
  name             = "flink-input-stream"
  shard_count      = 1
}

resource "aws_kinesis_stream" "output" {
  name             = "flink-output-stream"
  shard_count      = 1
}
