resource "aws_route53_hosted_zone" "primary" {
  name = "primary.example.com"

  vpc {
    vpc_id     = aws_vpc.main.id
    vpc_region = "us-east-1"
  }
}

resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_route53_record" "us_east_1_endpoint" {
  zone_id = aws_route53_hosted_zone.primary.zone_id
  name    = "endpoint-us-east-1.primary.example.com"
  type    = "A"
  ttl     = 300

  records = ["1.2.3.4"]

  health_check_id = aws_route53_health_check.us_east_1.id

  set_identifier = "us-east-1"
  latency_routing_policy {
    region = "us-east-1"
  }
}

resource "aws_route53_record" "eu_central_1_endpoint" {
  zone_id = aws_route53_hosted_zone.primary.zone_id
  name    = "endpoint-eu-central-1.primary.example.com"
  type    = "A"
  ttl     = 300

  records = ["5.6.7.8"]

  health_check_id = aws_route53_health_check.eu_central_1.id

  set_identifier = "eu-central-1"
  latency_routing_policy {
    region = "eu-central-1"
  }
}

resource "aws_route53_record" "weighted_lowest_load" {
  zone_id = aws_route53_hosted_zone.primary.zone_id
  name    = "api.primary.example.com"
  type    = "CNAME"

  weighted_routing_policy {
    weight = 50
  }

  alias {
    name                   = aws_route53_record.us_east_1_endpoint.name
    zone_id                = aws_route53_hosted_zone.primary.zone_id
    evaluate_target_health = true
  }

  set_identifier = "us-east-1-weighted"
}

resource "aws_route53_traffic_policy" "lowest_load" {
  name     = "lowest-load-policy"
  comment  = "Traffic policy for routing to lowest load endpoint"
  document = jsonencode({
    AWSPolicyFormatVersion = "2015-10-01"
    RecordType             = "A"
    StartRule              = "site_switch"
    Endpoints              = {
      us-east-1-endpoint = {
        Type = "value"
        Value = "1.2.3.4"
      }
      eu-central-1-endpoint = {
        Type = "value"
        Value = "5.6.7.8"
      }
    }
    Rules = {
      site_switch = {
        RuleType = "failover"
        Primary = {
          EndpointReference = "us-east-1-endpoint"
          HealthCheck       = aws_route53_health_check.us_east_1.id
        }
        Secondary = {
          EndpointReference = "eu-central-1-endpoint"
          HealthCheck       = aws_route53_health_check.eu_central_1.id
        }
      }
    }
  })
}

resource "aws_route53_traffic_policy_instance" "primary" {
  name                   = "api.primary.example.com"
  traffic_policy_id      = aws_route53_traffic_policy.lowest_load.id
