  bucket = aws_s3_bucket.wellcomecollection_platform_infra.id

  rule {
    id     = "tmp-prefix-expiration"
    status = "Enabled"

    filter {
      prefix = "tmp/"
    }

    expiration {
      days = 30
    }
  }

  rule {
    id     = "noncurrent-version-transition-and-expiration"
    status = "Enabled"

    noncurrent_version_transition {
      noncurrent_days = 30
      storage_class   = "STANDARD_IA"
    }

    noncurrent_version_expiration {
      noncurrent_days = 90
    }
  }
}

resource "aws_s3_bucket_policy" "wellcomecollection_platform_infra_deny_deletion" {
  bucket = aws_s3_bucket.wellcomecollection_platform_infra.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "DenyBucketDeletion"
        Effect = "Deny"
        Principal = {
          AWS = "*"
        }
        Action   = "s3:DeleteBucket"
        Resource = aws_s3_bucket.wellcomecollection_platform_infra.arn
      }
    ]
  })
}
```

