resource "aws_security_group" "ec2_fleet" {
  name_prefix = "ec2-fleet-"
  vpc_id      = aws_vpc.main.id

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "ec2-fleet-sg"
  }
}

resource "aws_launch_template" "main" {
  name_prefix   = "ec2-fleet-"
  image_id      = data.aws_ami.amazon_linux_2.id
  instance_type = "t3.micro"

  vpc_security_group_ids = [aws_security_group.ec2_fleet.id]

  tag_specifications {
    resource_type = "instance"
    tags = {
      Name = "ec2-fleet-instance"
    }
  }

  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_ec2_fleet" "main" {
  launch_template_config {
    launch_template_specification {
      launch_template_id = aws_launch_template.main.id
      version            = "$Latest"
    }

    override {
      subnet_id         = aws_subnet.private[0].id
      availability_zone = data.aws_availability_zones.available.names[0]
    }

    override {
      subnet_id         = aws_subnet.private[1].id
      availability_zone = data.aws_availability_zones.available.names[1]
    }
  }

  target_capacity_specification {
    default_target_capacity_type = "on-demand"
    total_target_capacity        = 9
    on_demand_target_capacity    = 5
    spot_target_capacity         = 4
  }

  terminate_instances = true

  tags = {
    Name = "main-ec2-fleet"
  }
}

