resource "aws_sagemaker_pipeline" "example" {
  pipeline_name         = "example-pipeline"
  pipeline_display_name = "Example Pipeline"

  pipeline_definition = jsonencode({
    Version = "2020-12-01"
    Steps = [
      {
        Name = "PreprocessData"
        Type = "Processing"
        Arguments = {
          ProcessingResources = {
            ClusterConfig = {
              InstanceCount  = 1
              InstanceType   = "ml.m5.xlarge"
              VolumeSizeInGB = 30
            }
          }
          AppSpecification = {
            ImageUri = "123456789012.dkr.ecr.us-west-2.amazonaws.com/preprocessing:latest"
          }
          ProcessingInputs = [
            {
              InputName = "input-1"
              S3Input = {
                S3Uri        = "s3://my-bucket/input/"
                LocalPath    = "/opt/ml/processing/input"
                S3DataType   = "S3Prefix"
                S3InputMode  = "File"
                S3DataDistributionType = "FullyReplicated"
              }
            }
          ]
          ProcessingOutputConfig = {
            Outputs = [
              {
                OutputName = "output-1"
                S3Output = {
                  S3Uri     = "s3://my-bucket/output/"
                  LocalPath = "/opt/ml/processing/output"
                  S3UploadMode = "EndOfJob"
                }
              }
            ]
          }
        }
      },
      {
        Name = "TrainModel"
        Type = "Training"
        Arguments = {
          AlgorithmSpecification = {
            TrainingImage = "123456789012.dkr.ecr.us-west-2.amazonaws.com/training:latest"
            TrainingInputMode = "File"
          }
          HyperParameters = {
            epochs = "10"
            batch_size = "32"
          }
          InputDataConfig = [
            {
              ChannelName = "training"
              DataSource = {
                S3DataSource = {
                  S3DataType = "S3Prefix"
                  S3Uri = "s3://my-bucket/output/"
                  S3DataDistributionType = "FullyReplicated"
                }
              }
            }
          ]
          OutputDataConfig = {
            S3OutputPath = "s3://my-bucket/model-output/"
          }
          ResourceConfig = {
            InstanceCount  = 1
            InstanceType   = "ml.m5.xlarge"
            VolumeSizeInGB = 50
          }
          StoppingCondition = {
            MaxRuntimeInSeconds = 3600
          }
        }
        DependsOn = ["PreprocessData"]
      }
    ]
  })

  role_arn = aws_iam_role.sagemaker_pipeline_role.arn

  tags = {
    Environment = "dev"
    Project     = "example"
  }
}

resource "aws_iam_role" "sagemaker_pipeline_role" {
  name = "sagemaker-pipeline-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "sagemaker.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "sagemaker_pipeline_policy" {
  name = "sagemaker-pipeline-policy"
  role = aws_iam_role.sagemaker_pipeline_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:ListBucket"
        ]
        Resource = [
          "arn:aws:s3:::my-bucket",
          "arn:aws:s3:::my-bucket/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "ecr:GetAuthorizationToken",
          "ecr:BatchCheckLayerAvailability",
          "ecr:GetDownloadUrlForLayer",
          "ecr:BatchGetImage"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "*"
      }
    ]
  })
}

