# Below is Terraform configuration for AWS ElastiCache (Redis) to minimize database queries.

resource "aws_elasticache_subnet_group" "example" {
  name       = "cache-subnet"
  subnet_ids = ["subnet-12345678", "subnet-87654321"]
}

resource "aws_security_group" "elasticache" {
  name_prefix = "elasticache-"

  ingress {
    from_port   = 6379
    to_port     = 6379
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }
}

resource "aws_elasticache_replication_group" "example" {
  replication_group_id = "app-cache"
  description          = "Redis cluster for query result caching"

  node_type            = "cache.t3.micro"
  port                 = 6379
  parameter_group_name = "default.redis7"

  num_cache_clusters         = 2
  automatic_failover_enabled = true

  subnet_group_name  = aws_elasticache_subnet_group.example.name
  security_group_ids = [aws_security_group.elasticache.id]

  at_rest_encryption_enabled = true
  transit_encryption_enabled = true

  snapshot_retention_limit = 5
  snapshot_window          = "00:00-05:00"

  tags = {
    Name = "Database Query Cache"
  }
}

resource "aws_elasticache_user" "example" {
  user_id       = "example-user"
  user_name     = "example-user"
  access_string = "on ~* +@all"
  engine        = "REDIS"

  authentication_mode {
    type      = "password"
    passwords = [random_password.redis_user.result]
  }
}

resource "random_password" "redis_user" {
  length  = 32
  special = true
}

