extracted_code:
resource "random_id" "suffix" {
  byte_length = 4
}

resource "aws_kms_key" "msk" {
  description             = "MSK Cluster Encryption Key"
  deletion_window_in_days = 7
}

resource "aws_kms_alias" "msk" {
  name          = "alias/msk-${random_id.suffix.hex}"
  target_key_id = aws_kms_key.msk.key_id
}

resource "aws_vpc" "msk" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "msk-vpc-${random_id.suffix.hex}"
  }
}

resource "aws_subnet" "msk" {
  count             = 3
  vpc_id            = aws_vpc.msk.id
  cidr_block        = "10.0.${count.index}.0/24"
  availability_zone = data.aws_availability_zones.available.names[count.index]

  tags = {
    Name = "msk-subnet-${count.index + 1}-${random_id.suffix.hex}"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

resource "aws_security_group" "msk" {
  name_prefix = "msk-"
  vpc_id      = aws_vpc.msk.id

  ingress {
    from_port   = 0
    to_port     = 65535
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.msk.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "msk-sg-${random_id.suffix.hex}"
  }
}

resource "aws_cloudwatch_log_group" "msk" {
  name              = "/aws/msk/cluster-${random_id.suffix.hex}"
  retention_in_days = 7
}

resource "aws_s3_bucket" "msk_logs" {
  bucket = "msk-logs-${random_id.suffix.hex}"
}

resource "aws_s3_bucket_server_side_encryption_configuration" "msk_logs" {
  bucket = aws_s3_bucket.msk_logs.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm     = "aws:kms"
      kms_master_key_id = aws_kms_key.msk.arn
    }
  }
}

resource "aws_s3_bucket_versioning" "msk_logs" {
  bucket = aws_s3_bucket.msk_logs.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_iam_role" "firehose" {
  name = "msk-firehose-role-${random_id.suffix.hex}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "firehose" {
  name = "msk-firehose-policy"
  role = aws_iam_role.firehose.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.msk_logs.arn,
          "${aws_s3_bucket.msk_logs.arn}/*"
        ]
      }
    ]
  })
}

resource "aws_kinesis_firehose_delivery_stream" "msk" {
  name        = "msk-firehose-${random_id.suffix.hex}"
  destination = "s3"

  s3_configuration {
    role_arn   = aws_iam_role.firehose.arn
    bucket_arn = aws_s3_bucket.msk_logs.arn
    prefix     = "msk-logs/"

    cloudwatch_logging_options {
      enabled         = true
      log_group_name  = aws_cloudwatch_log_group.msk.name
      log_stream_name = "firehose"
    }
  }
}

resource "aws_iam_role" "msk" {
  name = "msk-cluster-role-${random_id.suffix.hex}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kafka.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "msk" {
  name = "msk-cluster-policy"
  role = aws_iam_role.msk.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "${aws_cloudwatch_log_group.msk.arn}:*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject"
        ]
        Resource = "${aws_s3_bucket.msk_logs.arn}/*"
      },
      {
        Effect = "Allow"
        Action = [
          "firehose:PutRecord",
          "firehose:PutRecordBatch"
        ]
        Resource = aws_kinesis_firehose_delivery_stream.msk.arn
      }
    ]
  })
}

resource "aws_msk_cluster" "example" {
  cluster_name           = "msk-cluster-${random_id.suffix.hex}"
