  subnet_ids = aws_subnet.mysql[*].id

  tags = {
    Name = "MySQL subnet group"
  }
}

resource "aws_security_group" "mysql" {
  name_prefix = "mysql-sg-${random_id.suffix.hex}-"
  vpc_id      = aws_vpc.mysql.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.mysql.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_vpc" "mysql" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "mysql-vpc-${random_id.suffix.hex}"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

