  shard_count = 1
}

resource "aws_chime_voice_connector_streaming" "example" {
  voice_connector_id = aws_chime_voice_connector.example.id

  data_retention_in_hours = 24

  disabled = false

  streaming_notification_targets {
    notification_target = "EventBridge"
  }

  media_insights_configuration {
    configuration_arn = aws_chime_media_insights_configuration.example.arn
    disabled          = false
  }
}

resource "aws_chime_media_insights_configuration" "example" {
  name = "example-media-insights"

  resource_access_role_arn = aws_iam_role.chime_kinesis_access.arn

  realtime_media_insights_configuration {
    destination_configuration {
      kinesis_video_stream_configuration {
        stream_arn = aws_kinesis_stream.example.arn
      }
    }
  }
}

resource "aws_iam_role" "chime_kinesis_access" {
  name = "chime-kinesis-access-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "chime.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "chime_kinesis_access" {
  name = "chime-kinesis-access-policy"
  role = aws_iam_role.chime_kinesis_access.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "kinesis:PutRecord",
          "kinesis:PutRecords"
        ]
        Resource = aws_kinesis_stream.example.arn
      }
    ]
  })
}

