resource "aws_lambda_function" "grading_processor" {
  filename         = data.archive_file.lambda_zip.output_path
  function_name    = "${var.course_name}-grading-processor-${random_id.suffix.hex}"
  role             = aws_iam_role.lambda_role.arn
  handler          = "index.handler"
  runtime          = "python3.9"
  timeout          = 30
  source_code_hash = data.archive_file.lambda_zip.output_base64sha256

  environment {
    variables = {
      DYNAMODB_TABLE    = aws_dynamodb_table.grading_results.name
      SNS_TOPIC_ARN     = aws_sns_topic.grading_notifications.arn
      COURSE_NAME       = var.course_name
    }
  }
}

data "archive_file" "lambda_zip" {
  type        = "zip"
  output_path = "${path.module}/lambda_function.zip"

  source {
    content  = <<-EOF
    import json
    import boto3
    import os

    dynamodb = boto3.resource('dynamodb')
    sns = boto3.client('sns')

    def handler(event, context):
        table = dynamodb.Table(os.environ['DYNAMODB_TABLE'])
        topic_arn = os.environ['SNS_TOPIC_ARN']
        course_name = os.environ['COURSE_NAME']

        for record in event.get('Records', []):
            if record['eventName'] == 'INSERT':
                item = record['dynamodb']['NewImage']
                student_id = item.get('student_id', {}).get('S', 'unknown')
                assignment_id = item.get('assignment_id', {}).get('S', 'unknown')
                score = item.get('score', {}).get('N', 'N/A')
                status = item.get('status', {}).get('S', 'completed')

                message = f"""
    Autograding Complete for {course_name}

    Student: {student_id}
    Assignment: {assignment_id}
    Score: {score}
    Status: {status}
                """

                sns.publish(
                    TopicArn=topic_arn,
                    Subject=f"[{course_name}] Grading Complete - {assignment_id}",
                    Message=message
                )

        return {'statusCode': 200, 'body': json.dumps('Processing complete')}
    EOF
    filename = "index.py"
  }
}

