    name            = "SubmissionIndex"
    hash_key        = "assignment_id"
    range_key       = "submission_timestamp"
    projection_type = "ALL"
  }

  stream_enabled   = true
  stream_view_type = "NEW_IMAGE"

  point_in_time_recovery {
    enabled = true
  }

  lifecycle {
    prevent_destroy = false
    ignore_changes  = all
  }
}

