# CodeBuild Project for executing student code
resource "aws_codebuild_project" "autograder" {
  name          = "autograder-${random_id.suffix.hex}"
  description   = "Auto-grading system for CS course"
  build_timeout = "30"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type      = "S3"
    location  = aws_s3_bucket.build_artifacts.bucket
    path      = "build-output/"
    packaging = "ZIP"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "${aws_ecr_repository.grader.repository_url}:latest"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "SERVICE_ROLE"
    privileged_mode             = false

    environment_variable {
      name  = "SUBMISSION_BUCKET"
      value = aws_s3_bucket.submissions.bucket
    }

    environment_variable {
      name  = "RESULTS_BUCKET"
      value = aws_s3_bucket.build_artifacts.bucket
    }

    environment_variable {
      name  = "GRADING_TIMEOUT"
      value = "300"
    }
  }

  source {
    type      = "GITHUB"
    location  = "https://github.com/your-org/grading-starter-repo"
    buildspec = <<-EOT
      version: 0.2
      phases:
        pre_build:
          commands:
            - echo "Starting grading for $STUDENT_ID"
            - aws s3 cp s3://$SUBMISSION_BUCKET/submissions/$ASSIGNMENT_ID/$STUDENT_ID/ ./submission/ --recursive
            - aws s3 cp s3://$SUBMISSION_BUCKET/test-cases/$ASSIGNMENT_ID/ ./test-cases/ --recursive
        build:
          commands:
            - echo "Running tests..."
            - timeout $GRADING_TIMEOUT python3 /grader/run_tests.py ./submission ./test-cases --output /tmp/results.json || echo "Test execution completed or timed out"
        post_build:
          commands:
            - echo "Uploading results..."
            - aws s3 cp /tmp/results.json s3://$RESULTS_BUCKET/results/$ASSIGNMENT_ID/$STUDENT_ID-$(date +%s).json
            - aws s3 cp /tmp/results.json s3://$RESULTS_BUCKET/latest/$ASSIGNMENT_ID/$STUDENT_ID.json
      artifacts:
        files:
          - /tmp/results.json
        name: grading-results-$(date +%Y%m%d-%H%M%S)
      EOT
  }

  logs_config {
    cloudwatch_logs {
      group_name  = aws_cloudwatch_log_group.codebuild.name
      stream_name = "autograder"
    }

    s3_logs {
      status   = "ENABLED"
      location = "${aws_s3_bucket.build_artifacts.id}/build-logs/"
    }
  }
}

# CloudWatch Log Group for CodeBuild
resource "aws_cloudwatch_log_group" "codebuild" {
