}

# Lambda function to trigger grading on GitHub webhook
resource "aws_lambda_function" "webhook_handler" {
  function_name = "autograder-webhook-${random_id.suffix.hex}"
  role          = aws_iam_role.lambda_role.arn
  handler       = "index.handler"
  runtime       = "python3.11"
  timeout       = 30
  memory_size   = 256

  filename         = data.archive_file.lambda_zip.output_path
  source_code_hash = data.archive_file.lambda_zip.output_base64sha256

  environment {
    variables = {
      CODEBUILD_PROJECT = aws_codebuild_project.autograder.name
      SUBMISSIONS_BUCKET = aws_s3_bucket.submissions.bucket
      GITHUB_SECRET_ARN = aws_secretsmanager_secret.github_webhook.arn
    }
  }
}

data "archive_file" "lambda_zip" {
  type        = "zip"
  output_path = "/tmp/autograder_webhook.zip"

  source {
    content  = <<-EOF
      import json
      import boto3
      import hmac
      import hashlib
      import os
      import urllib.request

      codebuild = boto3.client('codebuild')
      s3 = boto3.client('s3')
      secretsmanager = boto3.client('secretsmanager')

      def handler(event, context):
          # Verify GitHub webhook signature
          body = event['body']
          headers = event.get('headers', {})

          # Get secret from Secrets Manager
          secret_response = secretsmanager.get_secret_value(
              SecretId=os.environ['GITHUB_SECRET_ARN']
          )
          webhook_secret = secret_response['SecretString']

          # Verify signature
          signature = headers.get('X-Hub-Signature-256', '')
          expected = 'sha256=' + hmac.new(
              webhook_secret.encode(),
              body.encode(),
              hashlib.sha256
          ).hexdigest()

          if not hmac.compare_digest(signature, expected):
              return {'statusCode': 401, 'body': 'Unauthorized'}

          payload = json.loads(body)

          # Handle push events
          if headers.get('X-GitHub-Event') == 'push':
              repo_url = payload['repository']['clone_url']
              commit_sha = payload['after']
              branch = payload['ref'].replace('refs/heads/', '')
              pusher = payload['pusher']['name']

              # Extract assignment info from repo name or branch
              assignment_id = branch  # or parse from repo name

              # Download and store submission
              submission_path = f"submissions/{assignment_id}/{pusher}/{commit_sha}"

              # Trigger CodeBuild
              response = codebuild.start_build(
                  projectName=os.environ['CODEBUILD_PROJECT'],
                  sourceVersion=commit_sha,
                  environmentVariablesOverride=[
                      {'name': 'STUDENT_ID', 'value': pusher},
                      {'name': 'ASSIGNMENT_ID', 'value': assignment_id},
                      {'name': 'COMMIT_SHA', 'value': commit_sha},
                      {'name': 'REPO_URL', 'value': repo_url}
                  ]
              )

              return {
                  'statusCode': 200,
                  'body': json.dumps({'buildId': response['build']['id']})
              }

          return {'statusCode': 200, 'body': 'Event processed'}
      EOF
    filename = "index.py"
  }
}

