```hcl
# Data sources for current AWS account and region
data "aws_caller_identity" "current" {}
data "aws_region" "current" {}

# S3 Bucket for storing grading outputs
resource "aws_s3_bucket" "grading_outputs" {
  bucket = "cs-autograding-outputs-${data.aws_caller_identity.current.account_id}-${data.aws_region.current.name}"
}

resource "aws_s3_bucket_versioning" "grading_outputs" {
  bucket = aws_s3_bucket.grading_outputs.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_server_side_encryption_configuration" "grading_outputs" {
  bucket = aws_s3_bucket.grading_outputs.id
  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

resource "aws_s3_bucket_lifecycle_configuration" "grading_outputs" {
  bucket = aws_s3_bucket.grading_outputs.id
  rule {
    id     = "expire-old-outputs"
    status = "Enabled"
    expiration {
      days = 90
    }
    noncurrent_version_expiration {
      noncurrent_days = 30
    }
  }
}

# IAM Role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "cs-autograding-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "codebuild_policy" {
  name = "cs-autograding-codebuild-policy"
  role = aws_iam_role.codebuild_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:GetObjectVersion",
          "s3:GetBucketAcl",
          "s3:GetBucketLocation"
        ]
        Resource = [
          aws_s3_bucket.grading_outputs.arn,
          "${aws_s3_bucket.grading_outputs.arn}/*"
        ]
      }
    ]
  })
}

# CloudWatch Log Group for CodeBuild
resource "aws_cloudwatch_log_group" "codebuild" {
  name              = "/aws/codebuild/cs-autograding"
  retention_in_days = 7
}

# CodeBuild Project for autograding
resource "aws_codebuild_project" "autograding" {
  name          = "cs-autograding-project"
  description   = "CodeBuild project for CS course autograding system"
  service_role  = aws_iam_role.codebuild_role.arn
  build_timeout = "60"

  artifacts {
    type = "S3"
    location = aws_s3_bucket.grading_outputs.bucket
    name     = "build-output"
    path     = "builds/"
    packaging = "ZIP"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:5.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"
    privileged_mode             = false

    environment_variable {
      name  = "GRADING_OUTPUT_BUCKET"
      value = aws_s3_bucket.grading_outputs.bucket
    }

    environment_variable {
      name  = "SUBMISSION_TIMEOUT"
      value = "300"
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/your-org/autograding-repo.git"
    git_clone_depth = 1
    buildspec       = "buildspec.yml"

    git_submodules_config {
      fetch_submodules = false
    }
  }

  logs_config {
    cloudwatch_logs {
      group_name  = aws_cloudwatch_log_group.codebuild.name
      stream_name = "autograding"
    }
  }

  tags = {
    Environment = "production"
    Purpose     = "autograding"
  }
}

# Webhook for GitHub integration (optional - triggers builds on push)
resource "aws_codebuild_webhook" "autograding" {
  project_name = aws_codebuild_project.autograding.name
  build_type   = "BUILD"

  filter_group {
    filter {
      type    = "EVENT"
      pattern = "PUSH"
    }

    filter {
      type    = "HEAD_REF"
      pattern = "refs/heads/main"
    }
  }

  filter_group {
    filter {
      type    = "EVENT"
      pattern = "PULL_REQUEST_CREATED,PULL_REQUEST_UPDATED"
    }
  }
}

# Secrets Manager for GitHub token (optional but recommended)
resource "aws_secretsmanager_secret" "github_token" {
  name        = "cs-autograding/github-token"
  description = "GitHub personal access token for CodeBuild"
}

resource "aws_secretsmanager_secret_version" "github_token" {
  secret_id     = aws_secretsmanager_secret.github_token.id
  secret_string = jsonencode({ token = "placeholder-replace-with-actual-token" })
}

# IAM policy for accessing GitHub token
resource "aws_iam_role_policy" "codebuild_secrets_policy" {
  name = "cs-autograding-secrets-policy"
  role = aws_iam_role.codebuild_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "secretsmanager:GetSecretValue"
        ]
        Resource = aws_secretsmanager_secret.github_token.arn
      }
    ]
  })
}

# SNS Topic for grading notifications
resource "aws_sns_topic" "grading_notifications" {
  name = "cs-autograding-notifications"
}

resource "aws_sns_topic_subscription" "email" {
  topic_arn = aws_sns_topic.grading_notifications.arn
  protocol  = "email"
  endpoint  = "instructor@university.edu" # Replace with actual email
}

# EventBridge rule for CodeBuild state changes
resource "aws_cloudwatch_event_rule" "codebuild_state" {
  name        = "cs-autograding-build-state"
  description = "Capture CodeBuild state changes"

  event_pattern = jsonencode({
    source      = ["aws.codebuild"]
    detail-type = ["CodeBuild Build State Change"]
    detail = {
      project-name = [aws_codebuild_project.autograding.name]
    }
  })
}

resource "aws_cloudwatch_event_target" "sns" {
  rule      = aws_cloudwatch_event_rule.codebuild_state.name
  target_id = "SendToSNS"
  arn       = aws_sns_topic.grading_notifications.arn
}

# DynamoDB table for tracking submissions (optional - for metadata storage)
resource "aws_dynamodb_table" "submissions" {
  name         = "cs-autograding-submissions"
  billing_mode = "PAY_PER_REQUEST"
  hash_key     = "submission_id"
  range_key    = "timestamp"

  attribute {
    name = "submission_id"
    type = "S"
  }

  attribute {
    name = "timestamp"
    type = "S"
  }

  attribute {
    name = "student_id"
    type = "S"
  }

  global_secondary_index {
    name            = "student-index"
    hash_key        = "student_id"
    range_key       = "timestamp"
    projection_type = "ALL"
  }

  point_in_time_recovery {
    enabled = true
  }

  tags = {
    Purpose = "autograding"
  }
}

# IAM policy for DynamoDB access
resource "aws_iam_role_policy" "codebuild_dynamodb_policy" {
  name = "cs-autograding-dynamodb-policy"
  role = aws_iam_role.codebuild_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "dynamodb:PutItem",
          "dynamodb:GetItem",
          "dynamodb:UpdateItem",
          "dynamodb:Query"
        ]
        Resource = [
          aws_dynamodb_table.submissions.arn,
          "${aws_dynamodb_table.submissions.arn}/index/*"
        ]
      }
    ]
  })
}

# VPC and Security Group for isolated grading environment (optional but recommended)
resource "aws_vpc" "grading" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "cs-autograding-vpc"
  }
}

resource "aws_subnet" "grading" {
  vpc_id                  = aws_vpc.grading.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "${data.aws_region.current.name}a"
  map_public_ip_on_launch = false

  tags = {
    Name = "cs-autograding-subnet"
  }
}

resource "aws_security_group" "codebuild" {
  name        = "cs-autograding-codebuild-sg"
  description = "Security group for CodeBuild autograding environment"
  vpc_id      = aws_vpc.grading.id

  egress {
    description = "HTTPS to AWS services"
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "cs-autograding-codebuild-sg"
  }
}

# VPC Endpoint for S3 (private connectivity)
resource "aws_vpc_endpoint" "s3" {
  vpc_id       = aws_vpc.grading.id
  service_name = "com.amazonaws.${data.aws_region.current.name}.s3"

  route_table_ids = [aws_route_table.grading.id]
}

resource "aws_route_table" "grading" {
  vpc_id = aws_vpc.grading.id

  tags = {
    Name = "cs-autograding-rt"
  }
}

resource "aws_route_table_association" "grading" {
  subnet_id      = aws_subnet.grading.id
  route_table_id = aws_route_table.grading.id
}

# Outputs
output "s3_bucket_name" {
  description = "Name of the S3 bucket for grading outputs"
  value       = aws_s3_bucket.grading_outputs.bucket
}

output "codebuild_project_name" {
  description = "Name of the CodeBuild project"
  value       = aws_codebuild_project.autograding.name
}

output "dynamodb_table_name" {
  description = "Name of the DynamoDB table for submissions"
  value       = aws_dynamodb_table.submissions.name
}

output "sns_topic_arn" {
  description = "ARN of the SNS topic for notifications"
  value       = aws_sns_topic.grading_notifications.arn
}
```

