# S3 Bucket for build artifacts and test cases
resource "aws_s3_bucket" "grading_artifacts" {
  bucket = "autograding-artifacts-${random_id.suffix.hex}"
}

resource "aws_s3_bucket_versioning" "grading_artifacts" {
  bucket = aws_s3_bucket.grading_artifacts.id
  versioning_configuration {
    status = "Enabled"
  }
}

# DynamoDB table for grading results
resource "aws_dynamodb_table" "grading_results" {
  name         = "autograding-results"
  billing_mode = "PAY_PER_REQUEST"
  hash_key     = "submission_id"
  range_key    = "timestamp"

  attribute {
    name = "submission_id"
    type = "S"
  }

  attribute {
    name = "timestamp"
    type = "S"
  }

  attribute {
    name = "student_id"
    type = "S"
  }

  global_secondary_index {
    name            = "StudentIndex"
    hash_key        = "student_id"
    range_key       = "timestamp"
    projection_type = "ALL"
  }
}

# CodeBuild Project for Autograding
resource "aws_codebuild_project" "autograder" {
  name          = "autograding-project"
  description   = "Autograding system for CS course submissions"
  build_timeout = "30"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "S3"
    location = aws_s3_bucket.grading_artifacts.bucket
    path = "build-output/"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:5.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"
    privileged_mode             = false

    environment_variable {
      name  = "DYNAMODB_TABLE"
      value = aws_dynamodb_table.grading_results.name
    }

    environment_variable {
      name  = "RESULTS_BUCKET"
      value = aws_s3_bucket.grading_artifacts.bucket
    }
  }

  vpc_config {
    vpc_id             = aws_vpc.grading_vpc.id
    subnets            = [aws_subnet.grading_private_subnet.id]
    security_group_ids = [aws_security_group.codebuild.id]
  }

  source {
    type      = "GITHUB"
    location  = "https://github.com/your-org/starter-code-repo.git"
    buildspec = <<-EOT
      version: 0.2

      phases:
        pre_build:
          commands:
            - echo "Starting autograding for submission..."
            - pip install awscli --quiet
        build:
          commands:
            - echo "Cloning student submission..."
            - git clone --depth 1 https://github.com/$${STUDENT_REPO} student_submission || exit 1
            - cd student_submission
            - echo "Running tests in isolated environment..."
            - python -m pytest /tests/ --json-report --json-report-file=results.json || true
        post_build:
          commands:
            - echo "Recording results..."
            - |
              python << 'PYEOF'
              import json
              import boto3
              import os
              from datetime import datetime

              # Load test results
              try:
                  with open('results.json', 'r') as f:
                      results = json.load(f)
              except:
                  results = {"summary": {"total": 0, "passed": 0, "failed": 0, "error": "Could not parse results"}}

              # Prepare record
              record = {
                  'submission_id': os.environ.get('CODEBUILD_BUILD_ID', 'unknown'),
                  'timestamp': datetime.utcnow().isoformat(),
                  'student_id': os.environ.get('STUDENT_ID', 'unknown'),
                  'assignment': os.environ.get('ASSIGNMENT_NAME', 'unknown'),
                  'repo_url': os.environ.get('STUDENT_REPO', 'unknown'),
                  'total_tests': results.get('summary', {}).get('total', 0),
                  'passed_tests': results.get('summary', {}).get('passed', 0),
                  'failed_tests': results.get('summary', {}).get('failed', 0),
                  'score': results.get('summary', {}).get('passed', 0) / max(results.get('summary', {}).get('total', 1), 1) * 100,
                  'details': json.dumps(results.get('tests', []))
              }

              # Store in DynamoDB
              dynamodb = boto3.resource('dynamodb', region_name=os.environ['AWS_REGION'])
              table = dynamodb.Table(os.environ['DYNAMODB_TABLE'])
              table.put_item(Item=record)

              # Also save full results to S3
              s3 = boto3.client('s3')
              s3.put_object(
                  Bucket=os.environ['RESULTS_BUCKET'],
                  Key=f"detailed-results/{record['submission_id']}.json",
                  Body=json.dumps(results, indent=2)
              )

              print(f"Graded submission: {record['score']:.1f}%")
              PYEOF
            - echo "Autograding complete"
      artifacts:
        files:
          - results.json
        name: grading-results-$(date +%Y%m%d-%H%M%S)
    EOT
  }

  logs_config {
    cloudwatch_logs {
      group_name  = aws_cloudwatch_log_group.autograding.name
      stream_name = "autograding-build"
    }
  }
}

# CloudWatch Log Group for build logs
resource "aws_cloudwatch_log_group" "autograding" {
  name              = "/aws/codebuild/autograding"
  retention_in_days = 30
}

# Lambda function to trigger builds on GitHub webhook
resource "aws_lambda_function" "webhook_handler" {
  function_name = "autograding-webhook-handler"
  role          = aws_iam_role.lambda_role.arn
  handler       = "index.handler"
  runtime       = "python3.9"
