  source_arn    = "${aws_api_gateway_rest_api.webhook.execution_arn}/*/*"
}

# Secrets Manager for GitHub webhook secret
resource "aws_secretsmanager_secret" "github_webhook" {
  name = "autograding/github-webhook-secret"
}

# Supporting resources
