data "archive_file" "lambda_zip" {
  type        = "zip"
  output_path = "${path.module}/lambda.zip"

  source {
    content  = <<-EOF
      import json
      import boto3
      import hmac
      import hashlib
      import os
      import base64

      def handler(event, context):
          # Verify GitHub webhook signature
          secret = get_secret()
          signature = event['headers'].get('X-Hub-Signature-256', '')

          body = event['body']
          if event.get('isBase64Encoded'):
              body = base64.b64decode(body).decode('utf-8')

          expected = 'sha256=' + hmac.new(
              secret.encode(),
              body.encode(),
              hashlib.sha256
          ).hexdigest()

          if not hmac.compare_digest(expected, signature):
              return {'statusCode': 401, 'body': 'Unauthorized'}

          # Parse webhook payload
          payload = json.loads(body)
          repo_url = payload.get('repository', {}).get('clone_url', '')
          student_id = payload.get('pusher', {}).get('name', 'unknown')
          assignment = payload.get('repository', {}).get('name', 'unknown')

          # Trigger CodeBuild
          codebuild = boto3.client('codebuild')
          codebuild.start_build(
              projectName=os.environ['CODEBUILD_PROJECT'],
              environmentVariablesOverride=[
                  {'name': 'STUDENT_REPO', 'value': repo_url.replace('https://github.com/', '')},
                  {'name': 'STUDENT_ID', 'value': student_id},
                  {'name': 'ASSIGNMENT_NAME', 'value': assignment}
              ]
          )

          return {'statusCode': 200, 'body': 'Build triggered'}

      def get_secret():
          import boto3
          secret_name = os.environ['GITHUB_SECRET_ARN'].split(':')[-1].split('-')[-1]
          client = boto3.client('secretsmanager')
          response = client.get_secret_value(SecretId=os.environ['GITHUB_SECRET_ARN'])
          return response['SecretString']
      EOF
    filename = "index.py"
  }
}
```

