  vpc_id      = aws_vpc.grading_vpc.id

  # No egress rules = no outbound internet access

  tags = {
    Name = "autograding-codebuild-sg"
  }
}

# CodeBuild Project for grading execution
resource "aws_codebuild_project" "grader" {
  name          = "autograding-executor"
  description   = "Executes student submissions in isolated environment"
  service_role  = aws_iam_role.codebuild_role.arn
  build_timeout = "60"

  artifacts {
    type = "S3"
    location = aws_s3_bucket.artifacts.bucket
    path = "build-output"
    packaging = "ZIP"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/amazonlinux2-x86_64-standard:4.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"
    privileged_mode             = false

    environment_variable {
      name  = "OUTPUT_BUCKET"
      value = aws_s3_bucket.outputs.bucket
    }

    environment_variable {
      name  = "SUBMISSION_BUCKET"
      value = aws_s3_bucket.submissions.bucket
    }
  }

  source {
    type      = "S3"
    location  = "${aws_s3_bucket.submissions.bucket}/source.zip"
    buildspec = <<-EOT
      version: 0.2
      phases:
        pre_build:
          commands:
            - echo "Starting grading execution in isolated environment"
            - echo "Internet access is disabled"
            - aws s3 cp s3://$SUBMISSION_BUCKET/$SUBMISSION_PATH ./submission/ --recursive || true
        build:
          commands:
            - echo "Executing student code with timeout and resource limits"
            - |
              timeout 300 bash -c '
                # Run student code in restricted environment
                # Network is disabled via VPC configuration
                # Resource limits enforced by container
                if [ -f ./submission/run.sh ]; then
                  chmod +x ./submission/run.sh
                  cd ./submission && ./run.sh 2>&1 | tee ../grading-output.log
                elif [ -f ./submission/main.py ]; then
                  cd ./submission && python3 main.py 2>&1 | tee ../grading-output.log
                else
                  echo "No recognized entry point found" | tee ../grading-output.log
                fi
              ' || echo "Execution timed out or failed" | tee -a grading-output.log
        post_build:
          commands:
            - echo "Uploading grading results"
            - aws s3 cp grading-output.log s3://$OUTPUT_BUCKET/$SUBMISSION_ID/grading-output.log
            - |
              cat << 'RESULT' > grading-result.json
              {
                "submission_id": "$SUBMISSION_ID",
                "timestamp": "$(date -u +%Y-%m-%dT%H:%M:%SZ)",
                "status": "completed",
                "vpc_execution": true,
                "network_isolated": true
              }
              RESULT
            - aws s3 cp grading-result.json s3://$OUTPUT_BUCKET/$SUBMISSION_ID/grading-result.json
      artifacts:
        files:
          - grading-output.log
          - grading-result.json
        discard-paths: no
    EOT
  }

  vpc_config {
    vpc_id             = aws_vpc.grading_vpc.id
    subnets            = [aws_subnet.private_subnet.id]
    security_group_ids = [aws_security_group.codebuild.id]
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "/aws/codebuild/autograding"
      stream_name = "executor"
    }
  }
}

