# Security group with no outbound internet access
resource "aws_security_group" "grading_sg" {
  name        = "autograding-sg"
  description = "Security group for autograding - no outbound internet"
  vpc_id      = aws_vpc.grading_vpc.id

  # No egress rules = no outbound internet access

  # Only allow inbound from VPC CIDR for CodeBuild
