# CodeBuild project for running student submissions
resource "aws_codebuild_project" "autograder" {
  name          = "autograding-runner"
  description   = "CodeBuild project for autograding student submissions"
  service_role  = aws_iam_role.codebuild_role.arn
  build_timeout = "60"

  artifacts {
    type = "S3"
    location = aws_s3_bucket.codebuild_artifacts.bucket
    namespace_type = "BUILD_ID"
    packaging = "ZIP"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/amazonlinux2-x86_64-standard:4.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"
    privileged_mode             = false

    environment_variable {
      name  = "SUBMISSIONS_BUCKET"
      value = aws_s3_bucket.submissions.bucket
    }

    environment_variable {
      name  = "OUTPUT_BUCKET"
      value = aws_s3_bucket.codebuild_artifacts.bucket
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/your-org/autograding-starter-repo.git"
    git_clone_depth = 1

    git_submodules_config {
      fetch_submodules = false
    }

    buildspec = <<-EOT
      version: 0.2
      phases:
        pre_build:
          commands:
            - echo "Starting autograding for submission"
            - aws s3 cp s3://$${SUBMISSIONS_BUCKET}/$${SUBMISSION_ID}/submission.zip ./submission.zip || echo "No submission.zip found"
            - unzip -q submission.zip -d ./student_submission || echo "No zip to extract"
        build:
          commands:
            - echo "Running grading tests in isolated environment"
            - |
              # Run student code with timeout and resource limits
              timeout 300 bash -c '
                cd ./student_submission
                # Run grading script - student code has no internet access
                python3 -c "
                  import sys
                  import json
                  import os

                  # Grade student submission
                  score = 0
                  max_score = 100
                  feedback = []

                  try:
                      # Run student code here with restrictions
                      exec(open("student_solution.py").read())
                      score = max_score
                      feedback.append("All tests passed")
                  except Exception as e:
                      feedback.append(f"Error: {str(e)}")

                  # Output results
                  result = {
                      "score": score,
                      "max_score": max_score,
                      "feedback": feedback,
                      "submission_id": os.environ.get("SUBMISSION_ID", "unknown"),
                      "timestamp": "$(date -u +%Y-%m-%dT%H:%M:%SZ)"
                  }
                  print(json.dumps(result))
                " > ../grading_output.json 2>&1 || echo "{"score": 0, "error": "Execution failed"}" > ../grading_output.json
              '
        post_build:
          commands:
            - echo "Uploading grading results"
            - aws s3 cp ./grading_output.json s3://$${OUTPUT_BUCKET}/results/$${SUBMISSION_ID}/result.json
            - echo "Grading complete"
      artifacts:
        files:
          - grading_output.json
        name: grading-results/$${SUBMISSION_ID}
      EOT
  }

  vpc_config {
    vpc_id             = aws_vpc.grading_vpc.id
    subnets            = [aws_subnet.grading_subnet.id]
    security_group_ids = [aws_security_group.grading_sg.id]
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "/aws/codebuild/autograding-runner"
      stream_name = "build-log"
    }

    s3_logs {
      status   = "ENABLED"
      location = "${aws_s3_bucket.codebuild_artifacts.id}/build-logs"
    }
  }

  tags = {
    Name = "autograding-runner"
  }
}

# CloudWatch Log Group for CodeBuild
resource "aws_cloudwatch_log_group" "codebuild" {
  name              = "/aws/codebuild/autograding-runner"
  retention_in_days = 7

  tags = {
    Name = "autograding-logs"
  }
}

