resource "aws_lambda_function" "webhook_handler" {
  filename         = data.archive_file.lambda_zip.output_path
  function_name    = "autograding-webhook-handler"
  role             = aws_iam_role.lambda_role.arn
  handler          = "index.handler"
  runtime          = "python3.11"
  timeout          = 30
  source_code_hash = data.archive_file.lambda_zip.output_base64sha256

  environment {
    variables = {
      CODEBUILD_PROJECT = aws_codebuild_project.autograder.name
      SUBMISSIONS_BUCKET = aws_s3_bucket.submissions.bucket
    }
  }

  tags = {
    Name = "autograding-webhook-handler"
  }
}

data "archive_file" "lambda_zip" {
  type        = "zip"
  output_path = "${path.module}/lambda_function.zip"

  source {
    content  = <<-EOF
      import json
      import boto3
      import os
      import hashlib
      import urllib.request

      codebuild = boto3.client('codebuild')
      s3 = boto3.client('s3')

      def handler(event, context):
          body = json.loads(event.get('body', '{}'))

          # Extract GitHub push event data
          repo_name = body.get('repository', {}).get('full_name', 'unknown')
          commit_sha = body.get('after', 'unknown')
          ref = body.get('ref', 'unknown')

          # Generate unique submission ID
          submission_id = hashlib.sha256(f"{repo_name}:{commit_sha}".encode()).hexdigest()[:16]

          # Download submission from GitHub
          archive_url = body.get('repository', {}).get('archive_url', '').replace('{archive_format}', 'zipball').replace('{/ref}', f"/{commit_sha}")

          try:
              req = urllib.request.Request(archive_url)
              req.add_header('User-Agent', 'Autograding-System')
              if 'GITHUB_TOKEN' in os.environ:
                  req.add_header('Authorization', f"token {os.environ['GITHUB_TOKEN']}")

              with urllib.request.urlopen(req, timeout=30) as response:
                  submission_data = response.read()

              # Upload to S3
              s3.put_object(
                  Bucket=os.environ['SUBMISSIONS_BUCKET'],
                  Key=f"{submission_id}/submission.zip",
                  Body=submission_data
              )
          except Exception as e:
              print(f"Failed to fetch submission: {e}")
              return {
                  'statusCode': 500,
                  'body': json.dumps({'error': 'Failed to fetch submission'})
              }

          # Trigger CodeBuild
          try:
              response = codebuild.start_build(
                  projectName=os.environ['CODEBUILD_PROJECT'],
                  environmentVariablesOverride=[
                      {
                          'name': 'SUBMISSION_ID',
                          'value': submission_id
                      },
                      {
                          'name': 'REPO_NAME',
                          'value': repo_name
                      },
                      {
                          'name': 'COMMIT_SHA',
                          'value': commit_sha
                      },
                      {
                          'name': 'REF',
                          'value': ref
                      }
                  ]
              )

              return {
                  'statusCode': 200,
                  'body': json.dumps({
                      'message': 'Grading started',
                      'submission_id': submission_id,
                      'build_id': response['build']['id']
                  })
              }
          except Exception as e:
              print(f"Failed to start build: {e}")
              return {
                  'statusCode': 500,
                  'body': json.dumps({'error': 'Failed to start grading'})
              }
      EOF
    filename = "index.py"
  }
}

