resource "aws_lambda_permission" "api_gateway" {
  statement_id  = "AllowAPIGatewayInvoke"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.webhook_handler.function_name
  principal     = "apigateway.amazonaws.com"
  source_arn    = "${aws_apigatewayv2_api.webhook_api.execution_arn}/*/*"
}

# DynamoDB table for grading results tracking
resource "aws_dynamodb_table" "grading_results" {
  name           = "autograding-results"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "submission_id"

  attribute {
    name = "submission_id"
    type = "S"
  }

  attribute {
    name = "student_id"
    type = "S"
  }

  attribute {
    name = "timestamp"
    type = "S"
  }

  global_secondary_index {
    name            = "student-timestamp-index"
    hash_key        = "student_id"
    range_key       = "timestamp"
    projection_type = "ALL"
  }

  point_in_time_recovery {
    enabled = true
  }

  tags = {
    Name = "autograding-results"
  }
}

# IAM role for DynamoDB access from CodeBuild
resource "aws_iam_role_policy_attachment" "codebuild_dynamodb" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonDynamoDBFullAccess"
}

# Secrets Manager for GitHub token
resource "aws_secretsmanager_secret" "github_token" {
  name        = "autograding/github-token"
  description = "GitHub personal access token for fetching submissions"

  tags = {
    Name = "autograding-github-token"
  }
}

# Outputs
output "webhook_url" {
  description = "URL for GitHub webhook configuration"
  value       = "${aws_apigatewayv2_api.webhook_api.api_endpoint}/prod/webhook"
}

output "submissions_bucket" {
  description = "S3 bucket for student submissions"
  value       = aws_s3_bucket.submissions.bucket
}

output "results_bucket" {
  description = "S3 bucket for grading outputs"
  value       = aws_s3_bucket.codebuild_artifacts.bucket
}

output "codebuild_project" {
  description = "CodeBuild project name"
  value       = aws_codebuild_project.autograder.name
}
