data "archive_file" "lambda_random_cat" {
  type        = "zip"
  output_path = "/tmp/lambda_random_cat.zip"

  source {
    content  = <<-EOF
    import json
    import boto3
    import random

    s3 = boto3.client('s3')
    BUCKET_NAME = '${aws_s3_bucket.cat_images.id}'

    def lambda_handler(event, context):
        try:
            response = s3.list_objects_v2(Bucket=BUCKET_NAME, MaxKeys=1000)

            if 'Contents' not in response or len(response['Contents']) == 0:
                return {
                    'statusCode': 404,
                    'headers': {
                        'Content-Type': 'application/json',
                        'Access-Control-Allow-Origin': '*'
                    },
                    'body': json.dumps({'error': 'No images found'})
                }

            # Filter for image files
            images = [obj['Key'] for obj in response['Contents'] 
                     if obj['Key'].lower().endswith(('.jpg', '.jpeg', '.png', '.gif', '.webp'))]

            if not images:
                return {
                    'statusCode': 404,
                    'headers': {
                        'Content-Type': 'application/json',
                        'Access-Control-Allow-Origin': '*'
                    },
                    'body': json.dumps({'error': 'No images found'})
                }

            random_image = random.choice(images)
            image_url = f"https://{BUCKET_NAME}.s3.amazonaws.com/{random_image}"

            return {
                'statusCode': 200,
                'headers': {
                    'Content-Type': 'application/json',
                    'Access-Control-Allow-Origin': '*'
                },
                'body': json.dumps({
                    'image_url': image_url,
                    'key': random_image
                })
            }

        except Exception as e:
            return {
                'statusCode': 500,
                'headers': {
                    'Content-Type': 'application/json',
                    'Access-Control-Allow-Origin': '*'
                },
                'body': json.dumps({'error': str(e)})
            }
    EOF
    filename = "index.py"
  }
}

resource "aws_lambda_function" "random_cat" {
  function_name = "random-cat-${random_id.suffix.hex}"
  role          = aws_iam_role.lambda_random_cat.arn
  handler       = "index.lambda_handler"
  runtime       = "python3.11"
  timeout       = 10

  filename         = data.archive_file.lambda_random_cat.output_path
  source_code_hash = data.archive_file.lambda_random_cat.output_base64sha256
}

resource "aws_lambda_permission" "api_gateway" {
  statement_id  = "AllowAPIGatewayInvoke"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.random_cat.function_name
  principal     = "apigateway.amazonaws.com"
  source_arn    = "${aws_api_gateway_rest_api.cat_api.execution_arn}/*/*"
}

# API Gateway Integration for random (Lambda)
resource "aws_api_gateway_integration" "random_get" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  resource_id = aws_api_gateway_resource.random.id
  http_method = aws_api_gateway_method.random_get.http_method

  integration_http_method = "POST"
  type                    = "AWS_PROXY"
  uri                     = aws_lambda_function.random_cat.invoke_arn
}

# API Gateway Deployment
resource "aws_api_gateway_deployment" "cat_api" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id

  depends_on = [
    aws_api_gateway_integration.upload_put,
    aws_api_gateway_integration.random_get
  ]

  triggers = {
    redeployment = sha1(jsonencode([
      aws_api_gateway_resource.upload.id,
      aws_api_gateway_resource.random.id,
      aws_api_gateway_method.upload_put.id,
      aws_api_gateway_method.random_get.id,
      aws_api_gateway_integration.upload_put.id,
      aws_api_gateway_integration.random_get.id,
    ]))
  }

  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_api_gateway_stage" "prod" {
  deployment_id = aws_api_gateway_deployment.cat_api.id
  rest_api_id   = aws_api_gateway_rest_api.cat_api.id
  stage_name    = "prod"
}

# Data source for current region
data "aws_region" "current" {}

# Outputs
output "api_endpoint" {
  value = "${aws_api_gateway_stage.prod.invoke_url}"
}

output "upload_endpoint" {
  value = "${aws_api_gateway_stage.prod.invoke_url}/upload/{filename}"
}

output "random_endpoint" {
  value = "${aws_api_gateway_stage.prod.invoke_url}/random"
}

output "s3_bucket_name" {
  value = aws_s3_bucket.cat_images.id
}

