  source {
    content  = <<-EOF
    import json
    import boto3
    import random

    s3 = boto3.client('s3')
    BUCKET_NAME = '${aws_s3_bucket.cat_images.id}'

    def lambda_handler(event, context):
        try:
            response = s3.list_objects_v2(Bucket=BUCKET_NAME, MaxKeys=1000)

            if 'Contents' not in response or len(response['Contents']) == 0:
                return {
                    'statusCode': 404,
                    'headers': {
                        'Content-Type': 'application/json',
                        'Access-Control-Allow-Origin': '*'
                    },
                    'body': json.dumps({'error': 'No images found'})
                }

            # Filter for image files
            images = [obj['Key'] for obj in response['Contents'] 
                     if obj['Key'].lower().endswith(('.jpg', '.jpeg', '.png', '.gif', '.webp'))]

            if not images:
                return {
                    'statusCode': 404,
                    'headers': {
                        'Content-Type': 'application/json',
                        'Access-Control-Allow-Origin': '*'
                    },
                    'body': json.dumps({'error': 'No images found'})
                }

            random_image = random.choice(images)
            image_url = f"https://{BUCKET_NAME}.s3.amazonaws.com/{random_image}"

            return {
                'statusCode': 200,
                'headers': {
                    'Content-Type': 'application/json',
                    'Access-Control-Allow-Origin': '*'
                },
                'body': json.dumps({
                    'image_url': image_url,
                    'key': random_image
                })
            }

        except Exception as e:
            return {
                'statusCode': 500,
                'headers': {
                    'Content-Type': 'application/json',
                    'Access-Control-Allow-Origin': '*'
                },
                'body': json.dumps({'error': str(e)})
            }
    EOF
    filename = "index.py"
  }
}

