# Archive for upload lambda code
data "archive_file" "lambda_upload" {
  type        = "zip"
  output_path = "${path.module}/lambda_upload.zip"

  source {
    content  = <<-EOF
import json
import base64
import boto3
import uuid
import os

s3 = boto3.client('s3')
BUCKET_NAME = os.environ['BUCKET_NAME']

def handler(event, context):
    try:
        # Parse the base64 encoded image from the request body
        body = json.loads(event.get('body', '{}'))
        image_data = body.get('image')
        content_type = body.get('content_type', 'image/jpeg')

        if not image_data:
            return {
                'statusCode': 400,
                'headers': {'Content-Type': 'application/json'},
                'body': json.dumps({'error': 'No image data provided'})
            }

        # Decode base64 image
        image_bytes = base64.b64decode(image_data)

        # Generate unique filename
        ext = content_type.split('/')[-1] if '/' in content_type else 'jpg'
        key = f"cats/{uuid.uuid4()}.{ext}"

        # Upload to S3
        s3.put_object(
            Bucket=BUCKET_NAME,
            Key=key,
            Body=image_bytes,
            ContentType=content_type
        )

        return {
            'statusCode': 200,
            'headers': {
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*'
            },
            'body': json.dumps({
                'message': 'Cat image uploaded successfully',
                'key': key,
                'url': f"https://{BUCKET_NAME}.s3.amazonaws.com/{key}"
            })
        }

    except Exception as e:
        return {
            'statusCode': 500,
            'headers': {'Content-Type': 'application/json'},
            'body': json.dumps({'error': str(e)})
        }
EOF
    filename = "index.py"
  }
}

# Archive for random cat lambda code
data "archive_file" "lambda_random" {
  type        = "zip"
  output_path = "${path.module}/lambda_random.zip"

  source {
    content  = <<-EOF
import json
import boto3
import random
import os

s3 = boto3.client('s3')
BUCKET_NAME = os.environ['BUCKET_NAME']

def handler(event, context):
    try:
        # List objects in the cats prefix
        response = s3.list_objects_v2(
            Bucket=BUCKET_NAME,
            Prefix='cats/'
        )

        objects = response.get('Contents', [])

        if not objects:
            return {
                'statusCode': 404,
                'headers': {'Content-Type': 'application/json'},
                'body': json.dumps({'error': 'No cat images found'})
            }

        # Select random cat image
        random_obj = random.choice(objects)
        key = random_obj['Key']

        # Generate presigned URL for the image
        url = s3.generate_presigned_url(
            'get_object',
            Params={
                'Bucket': BUCKET_NAME,
                'Key': key
            },
            ExpiresIn=3600
        )

        return {
            'statusCode': 200,
            'headers': {
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*'
            },
            'body': json.dumps({
                'key': key,
                'url': url,
                'size': random_obj['Size'],
                'last_modified': random_obj['LastModified'].isoformat()
            })
        }

    except Exception as e:
        return {
            'statusCode': 500,
            'headers': {'Content-Type': 'application/json'},
            'body': json.dumps({'error': str(e)})
        }
EOF
    filename = "index.py"
  }
}

