    content  = <<-EOF
import json
import boto3
import uuid
import base64
import random
import os

s3 = boto3.client('s3')
dynamodb = boto3.resource('dynamodb')

BUCKET_NAME = os.environ['BUCKET_NAME']
TABLE_NAME = os.environ['TABLE_NAME']

def handler(event, context):
    http_method = event['httpMethod']

    if http_method == 'POST':
        return upload_cat_image(event)
    elif http_method == 'GET':
        return get_random_cat_image(event)
    else:
        return {
            'statusCode': 405,
            'headers': {'Access-Control-Allow-Origin': '*'},
            'body': json.dumps({'error': 'Method not allowed'})
        }

def upload_cat_image(event):
    try:
        body = json.loads(event['body'])
        image_data = base64.b64decode(body['image'])
        content_type = body.get('contentType', 'image/jpeg')

        image_id = str(uuid.uuid4())
        key = f"cats/{image_id}"

        s3.put_object(
            Bucket=BUCKET_NAME,
            Key=key,
            Body=image_data,
            ContentType=content_type
        )

        table = dynamodb.Table(TABLE_NAME)
        table.put_item(Item={
            'imageId': image_id,
            's3Key': key,
            'contentType': content_type,
            'uploadedAt': str(context.aws_request_id)
        })

        return {
            'statusCode': 200,
            'headers': {'Access-Control-Allow-Origin': '*'},
            'body': json.dumps({'imageId': image_id, 'message': 'Cat image uploaded successfully'})
        }
    except Exception as e:
        return {
            'statusCode': 500,
            'headers': {'Access-Control-Allow-Origin': '*'},
            'body': json.dumps({'error': str(e)})
        }

def get_random_cat_image(event):
    try:
        table = dynamodb.Table(TABLE_NAME)
        response = table.scan()
        items = response.get('Items', [])

        if not items:
            return {
                'statusCode': 404,
                'headers': {'Access-Control-Allow-Origin': '*'},
                'body': json.dumps({'error': 'No cat images found'})
            }

        random_item = random.choice(items)
        image_id = random_item['imageId']
        key = random_item['s3Key']

        presigned_url = s3.generate_presigned_url(
            'get_object',
            Params={'Bucket': BUCKET_NAME, 'Key': key},
            ExpiresIn=3600
        )

        return {
            'statusCode': 200,
            'headers': {
                'Access-Control-Allow-Origin': '*',
                'Content-Type': 'application/json'
            },
            'body': json.dumps({
                'imageId': image_id,
                'downloadUrl': presigned_url,
                'contentType': random_item.get('contentType', 'image/jpeg')
            })
        }
    except Exception as e:
        return {
            'statusCode': 500,
            'headers': {'Access-Control-Allow-Origin': '*'},
            'body': json.dumps({'error': str(e)})
        }
    EOF
    filename = "index.py"
  }
}

