}

resource "aws_s3_bucket_ownership_controls" "cat_images" {
  bucket = aws_s3_bucket.cat_images.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_acl" "cat_images" {
  depends_on = [aws_s3_bucket_ownership_controls.cat_images]
  bucket     = aws_s3_bucket.cat_images.id
  acl        = "private"
}

# IAM role for Lambda execution
resource "aws_iam_role" "lambda_role" {
  name = "cat-images-lambda-role-${random_id.suffix.hex}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

# IAM policy for Lambda to access S3 and DynamoDB
resource "aws_iam_role_policy" "lambda_policy" {
  name = "cat-images-lambda-policy-${random_id.suffix.hex}"
  role = aws_iam_role.lambda_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.cat_images.arn,
          "${aws_s3_bucket.cat_images.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "dynamodb:PutItem",
          "dynamodb:GetItem",
          "dynamodb:Scan",
          "dynamodb:Query"
        ]
        Resource = aws_dynamodb_table.cat_images.arn
      }
    ]
  })
}

# CloudWatch log group for Lambda
resource "aws_cloudwatch_log_group" "lambda_logs" {
  name              = "/aws/lambda/cat-images-service-${random_id.suffix.hex}"
  retention_in_days = 14
}

# Lambda function for cat image service
resource "aws_lambda_function" "cat_service" {
  function_name = "cat-images-service-${random_id.suffix.hex}"
  role          = aws_iam_role.lambda_role.arn
  handler       = "index.handler"
  runtime       = "python3.11"
  timeout       = 30
  memory_size   = 512

  filename         = data.archive_file.lambda_zip.output_path
  source_code_hash = data.archive_file.lambda_zip.output_base64sha256

  environment {
    variables = {
      BUCKET_NAME = aws_s3_bucket.cat_images.bucket
      TABLE_NAME  = aws_dynamodb_table.cat_images.name
    }
  }

  depends_on = [aws_cloudwatch_log_group.lambda_logs]
}

# Lambda function code
data "archive_file" "lambda_zip" {
  type        = "zip"
  output_path = "${path.module}/lambda_function.zip"

  source {
    content  = <<-EOF
import json
import boto3
import uuid
import base64
import random
import os

s3 = boto3.client('s3')
dynamodb = boto3.resource('dynamodb')

BUCKET_NAME = os.environ['BUCKET_NAME']
TABLE_NAME = os.environ['TABLE_NAME']

def handler(event, context):
    http_method = event['httpMethod']

    if http_method == 'POST':
        return upload_cat_image(event)
    elif http_method == 'GET':
        return get_random_cat_image(event)
    else:
        return {
            'statusCode': 405,
            'headers': {'Access-Control-Allow-Origin': '*'},
            'body': json.dumps({'error': 'Method not allowed'})
        }

def upload_cat_image(event):
    try:
        body = json.loads(event['body'])
        image_data = base64.b64decode(body['image'])
        content_type = body.get('contentType', 'image/jpeg')

        image_id = str(uuid.uuid4())
        key = f"cats/{image_id}"

        s3.put_object(
            Bucket=BUCKET_NAME,
            Key=key,
            Body=image_data,
            ContentType=content_type
        )

        table = dynamodb.Table(TABLE_NAME)
        table.put_item(Item={
            'imageId': image_id,
            's3Key': key,
            'contentType': content_type,
            'uploadedAt': str(context.aws_request_id)
        })

        return {
            'statusCode': 200,
            'headers': {'Access-Control-Allow-Origin': '*'},
            'body': json.dumps({'imageId': image_id, 'message': 'Cat image uploaded successfully'})
        }
    except Exception as e:
        return {
            'statusCode': 500,
            'headers': {'Access-Control-Allow-Origin': '*'},
            'body': json.dumps({'error': str(e)})
        }

def get_random_cat_image(event):
    try:
        table = dynamodb.Table(TABLE_NAME)
        response = table.scan()
        items = response.get('Items', [])

        if not items:
            return {
                'statusCode': 404,
                'headers': {'Access-Control-Allow-Origin': '*'},
                'body': json.dumps({'error': 'No cat images found'})
            }

        random_item = random.choice(items)
        image_id = random_item['imageId']
        key = random_item['s3Key']

        presigned_url = s3.generate_presigned_url(
            'get_object',
            Params={'Bucket': BUCKET_NAME, 'Key': key},
            ExpiresIn=3600
        )

        return {
            'statusCode': 200,
            'headers': {
                'Access-Control-Allow-Origin': '*',
                'Content-Type': 'application/json'
            },
            'body': json.dumps({
                'imageId': image_id,
                'downloadUrl': presigned_url,
                'contentType': random_item.get('contentType', 'image/jpeg')
            })
        }
    except Exception as e:
        return {
            'statusCode': 500,
            'headers': {'Access-Control-Allow-Origin': '*'},
            'body': json.dumps({'error': str(e)})
        }
    EOF
    filename = "index.py"
  }
}

