data "aws_region" "current" {}
data "aws_caller_identity" "current" {}

# VPC and networking resources required for EC2
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "backup-demo-vpc"
  }
}

resource "aws_internet_gateway" "main" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "backup-demo-igw"
  }
}

resource "aws_subnet" "main" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "${data.aws_region.current.name}a"
  map_public_ip_on_launch = true

  tags = {
    Name = "backup-demo-subnet"
  }
}

resource "aws_route_table" "main" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.main.id
  }

  tags = {
    Name = "backup-demo-rt"
  }
}

resource "aws_route_table_association" "main" {
  subnet_id      = aws_subnet.main.id
  route_table_id = aws_route_table.main.id
}

# Security group for EC2
resource "aws_security_group" "main" {
  name_prefix = "backup-demo-sg"
  vpc_id      = aws_vpc.main.id

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "backup-demo-sg"
  }
}

# IAM role for EC2
resource "aws_iam_role" "ec2_role" {
  name = "backup-demo-ec2-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_instance_profile" "ec2_profile" {
  name = "backup-demo-ec2-profile"
  role = aws_iam_role.ec2_role.name
}

# Get latest Amazon Linux 2 AMI
data "aws_ami" "amazon_linux_2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }
}

# EC2 instance
resource "aws_instance" "main" {
  ami                    = data.aws_ami.amazon_linux_2.id
  instance_type          = "t3.micro"
  subnet_id              = aws_subnet.main.id
  vpc_security_group_ids = [aws_security_group.main.id]
  iam_instance_profile   = aws_iam_instance_profile.ec2_profile.name

  root_block_device {
    volume_size = 20
    encrypted   = true

    tags = {
      Name = "backup-demo-root-volume"
    }
  }

  tags = {
    Name        = "backup-demo-instance"
    BackupPlan  = "daily-backup"
  }

  depends_on = [aws_internet_gateway.main]
}

# EBS volume for additional data (optional, to demonstrate multi-resource backup)
resource "aws_ebs_volume" "data" {
  availability_zone = "${data.aws_region.current.name}a"
  size              = 10
  encrypted         = true

  tags = {
    Name       = "backup-demo-data-volume"
    BackupPlan = "daily-backup"
  }
}

resource "aws_volume_attachment" "data" {
  device_name = "/dev/sdf"
  volume_id   = aws_ebs_volume.data.id
  instance_id = aws_instance.main.id
}

# AWS Backup Vault
resource "aws_backup_vault" "main" {
  name        = "daily-backup-vault"
  kms_key_arn = aws_kms_key.backup.arn

  tags = {
    Name = "daily-backup-vault"
  }
}

# KMS key for backup encryption
resource "aws_kms_key" "backup" {
  description             = "KMS key for AWS Backup encryption"
  deletion_window_in_days = 7
  enable_key_rotation     = true

  tags = {
    Name = "backup-encryption-key"
  }
}

resource "aws_kms_alias" "backup" {
  name          = "alias/backup-key"
  target_key_id = aws_kms_key.backup.key_id
}

# AWS Backup Plan - Daily at 12:00 AM UTC
resource "aws_backup_plan" "daily" {
  name = "daily-ec2-backup-plan"

  rule {
    rule_name         = "daily-at-midnight"
    target_vault_name = aws_backup_vault.main.name
    schedule          = "cron(0 0 * * ? *)" // Daily at 12:00 AM UTC

    lifecycle {
      delete_after = 35 // Keep backups for 35 days
    }

    recovery_point_tags = {
      BackupType = "AutomatedDaily"
    }
  }

  advanced_backup_setting {
    resource_type = "EC2"
    backup_options = {
      WindowsVSS = "enabled"
    }
  }

  tags = {
    Name = "daily-ec2-backup-plan"
  }
}

# IAM role for AWS Backup
resource "aws_iam_role" "backup" {
  name = "aws-backup-service-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "backup.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "backup" {
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSBackupServiceRolePolicyForBackup"
  role       = aws_iam_role.backup.name
}

resource "aws_iam_role_policy_attachment" "restore" {
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSBackupServiceRolePolicyForRestores"
  role       = aws_iam_role.backup.name
}

# AWS Backup Selection - Select EC2 instances by tag
resource "aws_backup_selection" "ec2" {
  iam_role_arn = aws_iam_role.backup.arn
  name         = "ec2-daily-backup-selection"
  plan_id      = aws_backup_plan.daily.id

  selection_tag {
    type  = "STRINGEQUALS"
    key   = "BackupPlan"
    value = "daily-backup"
  }

  resources = [
    aws_instance.main.arn,
  ]
}

# SNS Topic for backup notifications (optional but recommended)
resource "aws_sns_topic" "backup_notifications" {
  name = "backup-job-notifications"

  tags = {
    Name = "backup-notifications"
  }
}

# CloudWatch Event Rule for backup job status
resource "aws_cloudwatch_event_rule" "backup_job" {
  name        = "backup-job-status"
  description = "Capture AWS Backup job status changes"

  event_pattern = jsonencode({
    source      = ["aws.backup"]
    detail-type = ["Backup Job State Change"]
  })
}

resource "aws_cloudwatch_event_target" "sns" {
  rule      = aws_cloudwatch_event_rule.backup_job.name
  target_id = "BackupSNSTarget"
  arn       = aws_sns_topic.backup_notifications.arn
}

# SNS Topic policy to allow CloudWatch Events
resource "aws_sns_topic_policy" "backup" {
  arn    = aws_sns_topic.backup_notifications.arn
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "AllowCloudWatchEvents"
        Effect = "Allow"
        Principal = {
          Service = "events.amazonaws.com"
        }
        Action   = "SNS:Publish"
        Resource = aws_sns_topic.backup_notifications.arn
      }
    ]
  })
}

