        type   = "metric"
        x      = 12
        y      = 0
        width  = 12
        height = 6
        properties = {
          metrics = [
            ["AWS/CloudFront", "BytesDownloaded", "Region", "Global", { stat = "Sum" }]
          ]
          period = 300
          region = "us-east-1"
          title  = "Bytes Downloaded"
        }
      },
      {
        type   = "metric"
        x      = 0
        y      = 6
        width  = 12
        height = 6
        properties = {
          metrics = [
            ["AWS/CloudFront", "ErrorRate", "Region", "Global", { stat = "Average" }]
          ]
          period = 300
          region = "us-east-1"
          title  = "Error Rate"
        }
      },
      {
        type   = "metric"
        x      = 12
        y      = 6
        width  = 12
        height = 6
        properties = {
          metrics = [
            ["AWS/Kinesis", "IncomingRecords", "StreamName", aws_kinesis_stream.video_analytics.name, { stat = "Sum" }]
          ]
          period = 300
          region = "us-east-1"
          title  = "Kinesis Incoming Records"
        }
      }
    ]
  })
}

