response:
```hcl
# Providers
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
  alias  = "primary"
}

provider "aws" {
  region = "eu-west-1"
  alias  = "eu"
}

provider "aws" {
  region = "ap-southeast-1"
  alias  = "ap"
}

# Random suffix for unique resource names
resource "random_id" "suffix" {
  byte_length = 4
}

# Primary S3 bucket for video content (origin)
resource "aws_s3_bucket" "video_content" {
  provider = aws.primary
  bucket   = "video-content-${random_id.suffix.hex}"

  tags = {
    Name        = "Video Content Origin"
    Environment = "Production"
  }
}

resource "aws_s3_bucket_versioning" "video_content" {
  provider = aws.primary
  bucket   = aws_s3_bucket.video_content.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_server_side_encryption_configuration" "video_content" {
  provider = aws.primary
  bucket   = aws_s3_bucket.video_content.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

# S3 bucket policy to allow CloudFront access
resource "aws_s3_bucket_policy" "video_content" {
  provider = aws.primary
  bucket   = aws_s3_bucket.video_content.id
  policy   = data.aws_iam_policy_document.s3_cloudfront_policy.json
}

data "aws_iam_policy_document" "s3_cloudfront_policy" {
  statement {
    sid    = "AllowCloudFrontAccess"
    effect = "Allow"
    principals {
      type        = "Service"
      identifiers = ["cloudfront.amazonaws.com"]
    }
    actions   = ["s3:GetObject"]
    resources = ["${aws_s3_bucket.video_content.arn}/*"]
    condition {
      test     = "StringEquals"
      variable = "AWS:SourceArn"
      values   = [aws_cloudfront_distribution.video_cdn.arn]
    }
  }
}

# Origin Access Control for CloudFront
resource "aws_cloudfront_origin_access_control" "video_oac" {
  provider                          = aws.primary
  name                              = "video-oac-${random_id.suffix.hex}"
  description                       = "OAC for video streaming"
  origin_access_control_origin_type = "s3"
  signing_behavior                  = "always"
  signing_protocol                  = "sigv4"
}

# CloudFront Distribution
resource "aws_cloudfront_distribution" "video_cdn" {
  provider = aws.primary
  enabled  = true
  comment  = "Video streaming CDN"

  # Origin for main S3 bucket
  origin {
    domain_name              = aws_s3_bucket.video_content.bucket_regional_domain_name
    origin_id                = "S3-video-content"
    origin_access_control_id = aws_cloudfront_origin_access_control.video_oac.id
  }

  # Origin for MediaPackage (live streaming)
  dynamic "origin" {
    for_each = aws_media_package_channel.live_channel
    content {
      domain_name = origin.value.hls_ingest[0].ingest_endpoints[0].url
      origin_id   = "MediaPackage-${origin.value.id}"
      custom_origin_config {
        http_port              = 80
        https_port             = 443
        origin_protocol_policy = "https-only"
        origin_ssl_protocols   = ["TLSv1.2"]
      }
    }
  }

  default_cache_behavior {
    allowed_methods  = ["GET", "HEAD", "OPTIONS"]
    cached_methods   = ["GET", "HEAD"]
    target_origin_id = "S3-video-content"

    forwarded_values {
      query_string = false
      cookies {
        forward = "none"
      }
    }

    viewer_protocol_policy = "redirect-to-https"
    min_ttl                = 0
    default_ttl            = 3600
    max_ttl                = 86400
    compress               = true

    lambda_function_association {
      event_type   = "origin-request"
      lambda_arn   = aws_lambda_function.edge_rewrite.qualified_arn
      include_body = false
    }
  }

  # Cache behavior for HLS/DASH streaming
  ordered_cache_behavior {
    path_pattern     = "/live/*"
    allowed_methods  = ["GET", "HEAD", "OPTIONS"]
    cached_methods   = ["GET", "HEAD"]
    target_origin_id = "S3-video-content"

    forwarded_values {
      query_string = true
      headers      = ["Origin", "Access-Control-Request-Headers", "Access-Control-Request-Method"]
      cookies {
        forward = "none"
      }
    }

    viewer_protocol_policy = "https-only"
    min_ttl                = 0
    default_ttl            = 1
    max_ttl                = 1

    smooth_streaming = true
  }

  # Cache behavior for video on demand
  ordered_cache_behavior {
    path_pattern     = "/vod/*"
    allowed_methods  = ["GET", "HEAD", "OPTIONS"]
    cached_methods   = ["GET", "HEAD"]
    target_origin_id = "S3-video-content"

    forwarded_values {
      query_string = false
      cookies {
        forward = "none"
      }
    }

    viewer_protocol_policy = "https-only"
    min_ttl                = 86400
    default_ttl            = 604800
    max_ttl                = 31536000
  }

  restrictions {
    geo_restriction {
      restriction_type = "none"
    }
  }

  viewer_certificate {
    cloudfront_default_certificate = false
    acm_certificate_arn            = aws_acm_certificate.video_cert.arn
    ssl_support_method             = "sni-only"
    minimum_protocol_version       = "TLSv1.2_2021"
  }

  logging_config {
    include_cookies = false
    bucket          = aws_s3_bucket.cloudfront_logs.bucket_domain_name
    prefix          = "cdn-logs/"
  }

  web_acl_id = aws_wafv2_web_acl.cloudfront_waf.arn

  tags = {
    Name        = "Video Streaming CDN"
    Environment = "Production"
  }
}

# S3 bucket for CloudFront logs
resource "aws_s3_bucket" "cloudfront_logs" {
  provider = aws.primary
  bucket   = "cloudfront-logs-${random_id.suffix.hex}"

  tags = {
    Name = "CloudFront Logs"
  }
}

# ACM Certificate (must be in us-east-1 for CloudFront)
resource "aws_acm_certificate" "video_cert" {
  provider          = aws.primary
  domain_name       = "video.${var.domain_name}"
  validation_method = "DNS"

  subject_alternative_names = [
    "*.video.${var.domain_name}"
  ]

  lifecycle {
    create_before_destroy = true
  }

  tags = {
    Name = "Video Streaming Certificate"
  }
}

variable "domain_name" {
  description = "Root domain name for the video platform"
  type        = string
  default     = "example.com"
}

# Route 53 Hosted Zone
data "aws_route53_zone" "primary" {
  provider     = aws.primary
  name         = var.domain_name
  private_zone = false
}

# Route 53 Records for CloudFront
resource "aws_route53_record" "video" {
  provider = aws.primary
  zone_id  = data.aws_route53_zone.primary.zone_id
  name     = "video.${var.domain_name}"
  type     = "A"

  alias {
    name                   = aws_cloudfront_distribution.video_cdn.domain_name
    zone_id                = aws_cloudfront_distribution.video_cdn.hosted_zone_id
    evaluate_target_health = false
  }
}

resource "aws_route53_record" "video_cert_validation" {
  provider = aws.primary
  for_each = {
    for dvo in aws_acm_certificate.video_cert.domain_validation_options : dvo.domain_name => {
      name   = dvo.resource_record_name
      record = dvo.resource_record_value
      type   = dvo.resource_record_type
    }
  }

  allow_overwrite = true
  name            = each.value.name
  records         = [each.value.record]
  ttl             = 60
  type            = each.value.type
  zone_id         = data.aws_route53_zone.primary.zone_id
}

resource "aws_acm_certificate_validation" "video_cert" {
  provider                = aws.primary
  certificate_arn         = aws_acm_certificate.video_cert.arn
  validation_record_fqdns = [for record in aws_route53_record.video_cert_validation : record.fqdn]
}

# WAF Web ACL for CloudFront
resource "aws_wafv2_web_acl" "cloudfront_waf" {
  provider = aws.primary
  name     = "video-streaming-waf-${random_id.suffix.hex}"
  scope    = "CLOUDFRONT"

  default_action {
    allow {}
  }

  # Rate limiting rule
  rule {
    name     = "RateLimitRule"
    priority = 1

    action {
      block {}
    }

    statement {
      rate_based_statement {
        limit              = 2000
        aggregate_key_type = "IP"
      }
    }

    visibility_config {
      cloudwatch_metrics_enabled = true
      metric_name                = "RateLimitRuleMetric"
      sampled_requests_enabled   = true
    }
  }

  # AWS Managed Rules - Common Rule Set
  rule {
    name     = "AWSManagedRulesCommonRuleSet"
    priority = 2

    override_action {
      none {}
    }

    statement {
      managed_rule_group_statement {
        name        = "AWSManagedRulesCommonRuleSet"
        vendor_name = "AWS"
      }
    }

    visibility_config {
      cloudwatch_metrics_enabled = true
      metric_name                = "AWSManagedRulesCommonRuleSetMetric"
      sampled_requests_enabled   = true
    }
  }

  # AWS Managed Rules - Known Bad Inputs
  rule {
    name     = "AWSManagedRulesKnownBadInputsRuleSet"
    priority = 3

    override_action {
      none {}
    }

    statement {
      managed_rule_group_statement {
        name        = "AWSManagedRulesKnownBadInputsRuleSet"
        vendor_name = "AWS"
      }
    }

    visibility_config {
      cloudwatch_metrics_enabled = true
      metric_name                = "AWSManagedRulesKnownBadInputsRuleSetMetric"
      sampled_requests_enabled   = true
    }
  }

  # Bot Control
  rule {
    name     = "AWSManagedRulesBotControlRuleSet"
    priority = 4

    override_action {
      none {}
    }

    statement {
      managed_rule_group_statement {
        name        = "AWSManagedRulesBotControlRuleSet"
        vendor_name = "AWS"
        managed_rule_group_configs {
          aws_managed_rules_bot_control_rule_set {
            inspection_level = "TARGETED"
          }
        }
      }
    }

    visibility_config {
      cloudwatch_metrics_enabled = true
      metric_name                = "AWSManagedRulesBotControlRuleSetMetric"
      sampled_requests_enabled   = true
    }
  }

  visibility_config {
    cloudwatch_metrics_enabled = true
    metric_name                = "video-streaming-waf-metric"
    sampled_requests_enabled   = true
  }

  tags = {
    Name = "Video Streaming WAF"
  }
}

# MediaConvert for video transcoding
resource "aws_media_convert_queue" "video_transcoding" {
  provider = aws.primary
  name     = "video-transcoding-${random_id.suffix.hex}"
  pricing_plan = "ON_DEMAND"

  tags = {
    Name = "Video Transcoding Queue"
  }
}

# IAM Role for MediaConvert
resource "aws_iam_role" "mediaconvert_role" {
  provider = aws.primary
  name     = "mediaconvert-role-${random_id.suffix.hex}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "mediaconvert.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "mediaconvert_policy" {
  provider = aws.primary
  name     = "mediaconvert-policy"
  role     = aws_iam_role.mediaconvert_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.video_content.arn,
          "${aws_s3_bucket.video_content.arn}/*"
        ]
      }
    ]
  })
}

# MediaPackage for live streaming
resource "aws_media_package_channel" "live_channel" {
  provider    = aws.primary
  channel_id  = "live-channel-${random_id.suffix.hex}"
  description = "Live streaming channel"

  tags = {
    Name = "Live Streaming Channel"
  }
}

# Elastic Transcoder (legacy but still useful for some workflows)
resource "aws_elastictranscoder_pipeline" "video_pipeline" {
  provider    = aws.primary
  input_bucket  = aws_s3_bucket.video_content.bucket
  output_bucket = aws_s3_bucket.video_content.bucket
  name          = "video-pipeline-${random_id.suffix.hex}"
  role          = aws_iam_role.elastictranscoder_role.arn

  content_config {
    bucket       = aws_s3_bucket.video_content.bucket
    storage_class = "Standard"
  }

  thumbnail_config {
    bucket       = aws_s3_bucket.video_content.bucket
    storage_class = "Standard"
  }
}

resource "aws_iam_role" "elastictranscoder_role" {
  provider = aws.primary
  name     = "elastictranscoder-role-${random_id.suffix.hex}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "elastictranscoder.amazonaws.com"
        }
      }
    ]
  })
}

# Lambda@Edge for URL signing and request modification
resource "aws_iam_role" "lambda_edge_role" {
  provider = aws.primary
  name     = "lambda-edge-role-${random_id.suffix.hex}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = [
            "lambda.amazonaws.com",
            "edgelambda.amazonaws.com"
          ]
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_edge_basic" {
  provider   = aws.primary
  role       = aws_iam_role.lambda_edge_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

resource "aws_lambda_function" "edge_rewrite" {
  provider      = aws.primary
  filename      = data.archive_file.lambda_edge_zip.output_path
  function_name = "edge-rewrite-${random_id.suffix.hex}"
  role          = aws_iam_role.lambda_edge_role.arn
  handler       = "index.handler"
  runtime       = "nodejs18.x"
  publish       = true

  source_code_hash = data.archive_file.lambda_edge_zip.output_base64sha256

  tags = {
    Name = "Edge Rewrite Lambda"
  }
}

data "archive_file" "lambda_edge_zip" {
  type        = "zip"
  output_path = "${path.module}/lambda_edge.zip"

  source {
    content  = <<-EOF
      exports.handler = async (event) => {
        const request = event.Records[0].cf.request;

        // Add custom headers for video optimization
        request.headers['x-custom-header'] = [{ key: 'X-Custom-Header', value: 'video-streaming' }];

        // Rewrite URLs for adaptive bitrate streaming
        if (request.uri.match(/\.m3u8$/) || request.uri.match(/\.mpd$/)) {
          request.headers['cache-control'] = [{ key: 'Cache-Control', value: 'max-age=1' }];
        }

        return request;
      };
    EOF
    filename = "index.js"
  }
}

# DynamoDB for user session management and viewing history
resource "aws_dynamodb_table" "user_sessions" {
  provider     = aws.primary
  name         = "user-sessions-${random_id.suffix.hex}"
  billing_mode = "PAY_PER_REQUEST"
  hash_key     = "user_id"
  range_key    = "session_id"

  attribute {
    name = "user_id"
    type = "S"
  }

  attribute {
    name = "session_id"
    type = "S"
  }

  attribute {
    name = "timestamp"
    type = "N"
  }

  global_secondary_index {
    name            = "timestamp-index"
    hash_key        = "user_id"
    range_key       = "timestamp"
    projection_type = "ALL"
  }

  point_in_time_recovery {
    enabled = true
  }

  server_side_encryption {
    enabled = true
  }

  tags = {
    Name = "User Sessions Table"
  }
}

# DynamoDB Global Tables for multi-region replication
resource "aws_dynamodb_global_table" "user_sessions_global" {
  provider = aws.primary
  name     = aws_dynamodb_table.user_sessions.name

  replica {
    region_name = "us-east-1"
  }

  replica {
    region_name = "eu-west-1"
  }

  replica {
    region_name = "ap-southeast-1"
  }
}

# ElastiCache Redis for session caching and real-time features
resource "aws_elasticache_subnet_group" "video_cache" {
  provider   = aws.primary
  name       = "video-cache-subnet-${random_id.suffix.hex}"
  subnet_ids = aws_subnet.private[*].id
}

resource "aws_elasticache_replication_group" "video_cache" {
  provider = aws.primary
  replication_group_id = "video-cache-${random_id.suffix.hex}"
  description          = "Redis cluster for video streaming"

  node_type            = "cache.r6g.large"
  num_cache_clusters   = 2
  automatic_failover_enabled = true
  multi_az_enabled     = true

  at_rest_encryption_enabled = true
  transit_encryption_enabled = true

  subnet_group_name  = aws_elasticache_subnet_group.video_cache.name
  security_group_ids = [aws_security_group.redis.id]

  tags = {
    Name = "Video Streaming Cache"
  }
}

# VPC and Networking
resource "aws_vpc" "main" {
  provider   = aws.primary
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "Video Streaming VPC"
  }
}

resource "aws_subnet" "private" {
  provider          = aws.primary
  count             = 3
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.${count.index + 1}.0/24"
  availability_zone = data.aws_availability_zones.available.names[count.index]

  tags = {
    Name = "Private Subnet ${count.index + 1}"
    Type = "Private"
  }
}

data "aws_availability_zones" "available" {
  provider = aws.primary
  state    = "available"
}

resource "aws_security_group" "redis" {
  provider    = aws.primary
  name        = "redis-sg-${random_id.suffix.hex}"
  description = "Security group for Redis"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 6379
    to_port     = 6379
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "Redis Security Group"
  }
}

# Kinesis for real-time analytics
resource "aws_kinesis_stream" "video_analytics" {
  provider     = aws.primary
  name         = "video-analytics-${random_id.suffix.hex}"
  shard_count  = 4

  stream_mode_details {
    stream_mode = "PROVISIONED"
  }

  encryption_type = "KMS"

  tags = {
    Name = "Video Analytics Stream"
  }
}

# Kinesis Firehose for S3 data lake
resource "aws_kinesis_firehose_delivery_stream" "video_events" {
  provider    = aws.primary
  name        = "video-events-${random_id.suffix.hex}"
  destination = "s3"

  s3_configuration {
    role_arn   = aws_iam_role.firehose_role.arn
    bucket_arn = aws_s3_bucket.analytics_data.arn

    buffer_size     = 5
    buffer_interval = 300

    compression_format = "GZIP"

    cloudwatch_logging_options {
      enabled         = true
      log_group_name  = aws_cloudwatch_log_group.firehose.name
      log_stream_name = "S3Delivery"
    }
  }
}

resource "aws_s3_bucket" "analytics_data" {
  provider = aws.primary
  bucket   = "video-analytics-data-${random_id.suffix.hex}"

  tags = {
    Name = "Video Analytics Data Lake"
  }
}

resource "aws_cloudwatch_log_group" "firehose" {
  provider = aws.primary
  name     = "/aws/kinesisfirehose/video-events-${random_id.suffix.hex}"

  tags = {
    Name = "Firehose Logs"
  }
}

resource "aws_iam_role" "firehose_role" {
  provider = aws.primary
  name     = "firehose-role-${random_id.suffix.hex}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

# SNS for notifications
resource "aws_sns_topic" "video_notifications" {
  provider = aws.primary
  name     = "video-notifications-${random_id.suffix.hex}"

  tags = {
    Name = "Video Notifications"
  }
}

# SQS for video processing queue
resource "aws_sqs_queue" "video_processing" {
  provider = aws.primary
  name     = "video-processing-${random_id.suffix.hex}"

  visibility_timeout_seconds = 300
  message_retention_seconds  = 86400

  tags = {
    Name = "Video Processing Queue"
  }
}

# CloudWatch Dashboard
resource "aws_cloudwatch_dashboard" "video_streaming" {
  provider       = aws.primary
  dashboard_name = "video-streaming-${random_id.suffix.hex}"

  dashboard_body = jsonencode({
    widgets = [
      {
        type   = "metric"
        x      = 0
        y      = 0
        width  = 12
        height = 6
        properties = {
          metrics = [
            ["AWS/CloudFront", "Requests", "Region", "Global", { stat = "Sum" }]
          ]
          period = 300
          region = "us-east-1"
          title  = "CloudFront Requests"
        }
      },
      {
        type   = "metric"
        x      = 12
        y      = 0
        width  = 12
        height = 6
        properties = {
          metrics = [
            ["AWS/CloudFront", "BytesDownloaded", "Region", "Global", { stat = "Sum" }]
          ]
          period = 300
          region = "us-east-1"
          title  = "Bytes Downloaded"
        }
      },
      {
        type   = "metric"
        x      = 0
        y      = 6
        width  = 12
        height = 6
        properties = {
          metrics = [
            ["AWS/CloudFront", "ErrorRate", "Region", "Global", { stat = "Average" }]
          ]
          period = 300
          region = "us-east-1"
          title  = "Error Rate"
        }
      },
      {
        type   = "metric"
        x      = 12
        y      = 6
        width  = 12
        height = 6
        properties = {
          metrics = [
            ["AWS/Kinesis", "IncomingRecords", "StreamName", aws_kinesis_stream.video_analytics.name, { stat = "Sum" }]
          ]
          period = 300
          region = "us-east-1"
          title  = "Kinesis Incoming Records"
        }
      }
    ]
  })
}

# Outputs
output "cloudfront_domain_name" {
  description = "CloudFront distribution domain name"
  value       = aws_cloudfront_distribution.video_cdn.domain_name
}

output "video_endpoint" {
  description = "Video streaming endpoint"
  value       = "https://${aws_route53_record.video.name}"
}

output "s3_bucket_name" {
  description = "S3 bucket for video content"
  value       = aws_s3_bucket.video_content.bucket
}

output "mediaconvert_queue_arn" {
  description = "MediaConvert queue ARN"
  value       = aws_media_convert_queue.video_transcoding.arn
}

output "kinesis_stream_name" {
  description = "Kinesis analytics stream name"
  value       = aws_kinesis_stream.video_analytics.name
}
```

