}

# Auto Scaling Group
resource "aws_autoscaling_group" "video_streaming" {
  name                = "video-streaming-asg"
  vpc_zone_identifier = module.vpc.private_subnets
  target_group_arns   = [aws_lb_target_group.video_streaming.arn]
  health_check_type   = "ELB"
  desired_capacity    = 3
  min_size            = 2
  max_size            = 10

  launch_template {
    id      = aws_launch_template.video_streaming.id
    version = "$Latest"
  }

  tag {
    key                 = "Name"
    value               = "video-streaming-server"
    propagate_at_launch = true
  }
}

# Route53 Hosted Zone
resource "aws_route53_zone" "video_streaming" {
  name = "videostream.example.com"

  tags = {
    Name = "video-streaming-zone"
  }
}

# Route53 DNS Record for ALB
resource "aws_route53_record" "video_streaming" {
  zone_id = aws_route53_zone.video_streaming.zone_id
  name    = "stream.videostream.example.com"
  type    = "A"

  alias {
    name                   = aws_lb.video_streaming.dns_name
    zone_id                = aws_lb.video_streaming.zone_id
    evaluate_target_health = true
  }
}

# CloudFront Distribution for global content delivery
resource "aws_cloudfront_distribution" "video_streaming" {
  origin {
    domain_name = aws_lb.video_streaming.dns_name
    origin_id   = "video-streaming-alb"

    custom_origin_config {
      http_port              = 80
      https_port             = 443
      origin_protocol_policy = "http-only"
      origin_ssl_protocols   = ["TLSv1.2"]
    }
  }

  enabled             = true
  is_ipv6_enabled     = true
  comment             = "Video streaming platform CDN"
  default_root_object = "index.html"

  default_cache_behavior {
    allowed_methods  = ["DELETE", "GET", "HEAD", "OPTIONS", "PATCH", "POST", "PUT"]
    cached_methods   = ["GET", "HEAD"]
    target_origin_id = "video-streaming-alb"

    forwarded_values {
      query_string = false

      cookies {
        forward = "none"
      }
    }

    viewer_protocol_policy = "allow-all"
    min_ttl                = 0
    default_ttl            = 3600
    max_ttl                = 86400
  }

  restrictions {
    geo_restriction {
      restriction_type = "none"
    }
  }

  viewer_certificate {
    cloudfront_default_certificate = true
  }

  tags = {
    Name = "video-streaming-cdn"
  }
}

# S3 Bucket for video storage
resource "aws_s3_bucket" "video_storage" {
  bucket = "video-streaming-storage-${random_id.bucket_suffix.hex}"

  tags = {
    Name = "video-streaming-storage"
  }
}

resource "random_id" "bucket_suffix" {
  byte_length = 4
}

resource "aws_s3_bucket_versioning" "video_storage" {
  bucket = aws_s3_bucket.video_storage.id
  versioning_configuration {
    status = "Enabled"
  }
}

# IAM Role for EC2 instances
resource "aws_iam_role" "video_streaming" {
  name = "video-streaming-ec2-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "video_streaming" {
  name = "video-streaming-policy"
  role = aws_iam_role.video_streaming.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.video_storage.arn,
          "${aws_s3_bucket.video_storage.arn}/*"
        ]
      }
    ]
  })
}

resource "aws_iam_instance_profile" "video_streaming" {
  name = "video-streaming-profile"
  role = aws_iam_role.video_streaming.name
}
```

