  subnet_ids = [aws_subnet.private_a.id, aws_subnet.private_b.id]

  tags = {
    Name = "RDS Subnet Group"
  }
}

resource "aws_kms_key" "rds" {
  description             = "KMS key for RDS encryption"
  deletion_window_in_days = 7
  enable_key_rotation     = true

  tags = {
    Name = "rds-kms-key-${random_id.suffix.hex}"
  }
}

resource "aws_kms_alias" "rds" {
  name          = "alias/rds-key-${random_id.suffix.hex}"
  target_key_id = aws_kms_key.rds.key_id
}

resource "aws_security_group" "rds" {
  name        = "rds-postgres-sg-${random_id.suffix.hex}"
  description = "Security group for PostgreSQL RDS"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "PostgreSQL from VPC"
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "rds-postgres-sg-${random_id.suffix.hex}"
  }
}

resource "aws_db_parameter_group" "postgres" {
  name        = "postgres-params-${random_id.suffix.hex}"
  family      = "postgres15"
  description = "Custom parameter group for PostgreSQL"

  parameter {
    name  = "log_connections"
    value = "1"
  }

  parameter {
    name  = "log_disconnections"
    value = "1"
  }

  parameter {
    name  = "log_duration"
    value = "1"
  }

  parameter {
    name  = "ssl"
    value = "1"
  }

  tags = {
    Name = "postgres-params-${random_id.suffix.hex}"
  }
}

resource "aws_db_instance" "postgres" {
  identifier = "postgres-protected-${random_id.suffix.hex}"

  engine         = "postgres"
  engine_version = "15.4"
  instance_class = "db.t3.medium"

  allocated_storage     = 100
  max_allocated_storage = 200
  storage_type          = "gp3"
  storage_encrypted     = true
  kms_key_id            = aws_kms_key.rds.arn

  db_name  = "appdatabase"
  username = "dbadmin"
  password = random_password.db.result

  multi_az               = true
  db_subnet_group_name   = aws_db_subnet_group.main.name
  vpc_security_group_ids = [aws_security_group.rds.id]
  parameter_group_name   = aws_db_parameter_group.postgres.name

  publicly_accessible    = false
  skip_final_snapshot    = false
  final_snapshot_identifier = "pgsnapshot"

  backup_retention_period = 7
  backup_window           = "03:00-04:00"
  maintenance_window      = "Mon:04:00-Mon:05:00"

  deletion_protection = true

  tags = {
    Name        = "postgres-protected-${random_id.suffix.hex}"
    Environment = "production"
  }
}

