resource "aws_db_instance" "airbyte_postgres" {
  identifier           = "airbyte-postgres-${random_id.suffix.hex}"
  engine               = "postgres"
  engine_version       = "15"
  instance_class       = "db.t3.medium"
  allocated_storage    = 500
  max_allocated_storage = 1000
  storage_type         = "gp3"
  storage_encrypted    = true

  db_name  = "airbyte"
  username = "airbyte"
  password = random_password.db.result

  db_subnet_group_name   = aws_db_subnet_group.airbyte.name
  vpc_security_group_ids = [aws_security_group.airbyte_rds.id]

  publicly_accessible = true
  skip_final_snapshot = true

  backup_retention_period = 7
  maintenance_window      = "Mon:03:00-Mon:04:00"
  backup_window           = "02:00-03:00"

  auto_minor_version_upgrade = true
  deletion_protection        = false

  performance_insights_enabled    = true
  performance_insights_retention_period = 7

  monitoring_interval = 60
  monitoring_role_arn = aws_iam_role.rds_monitoring.arn

  enabled_cloudwatch_logs_exports = ["postgresql", "upgrade"]

  tags = {
    Name        = "Airbyte PostgreSQL 15"
    Environment = "test"
    Purpose     = "airbyte-connector-tests"
  }
}

resource "aws_iam_role" "rds_monitoring" {
  name = "airbyte-rds-monitoring-role-${random_id.suffix.hex}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "monitoring.rds.amazonaws.com"
        }
      }
    ]
  })

  managed_policy_arns = ["arn:aws:iam::aws:policy/service-role/AmazonRDSEnhancedMonitoringRole"]
}

variable "vpc_id" {
  description = "VPC ID for RDS deployment"
  type        = string
}

variable "public_subnet_ids" {
  description = "List of public subnet IDs for RDS subnet group"
  type        = list(string)
}

variable "allowed_cidr_blocks" {
  description = "CIDR blocks allowed to access RDS"
  type        = list(string)
  default     = ["0.0.0.0/0"]
}

output "rds_endpoint" {
  description = "RDS instance endpoint"
  value       = aws_db_instance.airbyte_postgres.endpoint
}

output "rds_username" {
  description = "RDS master username"
  value       = aws_db_instance.airbyte_postgres.username
}

output "rds_password" {
  description = "RDS master password"
  value       = random_password.db.result
  sensitive   = true
}

