resource "aws_lightsail_instance" "mysql" {
  name              = "mysql-server-${random_id.suffix.hex}"
  availability_zone = "us-east-1a"
  blueprint_id      = "amazon_linux_2"
  bundle_id         = "nano_2_0"
  user_data         = <<-EOF
    #!/bin/bash
    yum update -y
    amazon-linux-extras install mariadb10.5 -y
    systemctl start mariadb
    systemctl enable mariadb

    # Secure installation and create database
    mysql -e "UPDATE mysql.user SET Password=PASSWORD('${random_password.db.result}') WHERE User='root';"
    mysql -e "DELETE FROM mysql.user WHERE User='';"
    mysql -e "DROP DATABASE IF EXISTS test;"
    mysql -e "DELETE FROM mysql.db WHERE Db='test' OR Db='test\_%';"
    mysql -e "CREATE DATABASE myapp;"
    mysql -e "FLUSH PRIVILEGES;"

    # Configure to listen on all interfaces
    sed -i 's/bind-address.*/bind-address = 0.0.0.0/' /etc/my.cnf
    systemctl restart mariadb
  EOF
}

