resource "aws_glacier_vault_lock" "example" {
  vault_name = aws_glacier_vault.example.name

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "deny-deletion"
        Effect = "Deny"
        Principal = {
          AWS = "*"
        }
        Action   = "glacier:DeleteArchive"
        Resource = "${aws_glacier_vault.example.arn}/*"
        Condition = {
          NumericLessThan = {
            "aws:EpochTime" = "4102444800" # January 1, 2100
          }
        }
      }
    ]
  })

  complete_lock = false
}

