  name          = "alias/backup-key-${random_id.bucket_suffix.hex}"
  target_key_id = aws_kms_key.backup.key_id
}

resource "aws_backup_plan" "main" {
  name = "main-backup-plan"

  rule {
    rule_name         = "daily-backups"
    target_vault_name = aws_backup_vault.main.name
    schedule          = "cron(0 5 ? * * *)"

    lifecycle {
      delete_after = 35
    }

    copy_action {
      destination_vault_arn = aws_backup_vault.secondary.arn

      lifecycle {
        delete_after = 2555 // 7 years in secondary vault
      }
    }
  }

  rule {
    rule_name         = "monthly-archive"
    target_vault_name = aws_backup_vault.main.name
    schedule          = "cron(0 5 1 * ? *)"

    lifecycle {
      cold_storage_after = 30
      delete_after       = 2555
    }
  }
}

resource "aws_backup_vault" "secondary" {
  provider    = aws.west
  name        = "secondary-backup-vault-${random_id.bucket_suffix.hex}"
  kms_key_arn = aws_kms_key.backup_secondary.arn
}

resource "aws_kms_key" "backup_secondary" {
  provider                = aws.west
  description             = "KMS key for secondary backup encryption"
  deletion_window_in_days = 30
  enable_key_rotation     = true
}

resource "aws_backup_selection" "main" {
  iam_role_arn = aws_iam_role.backup.arn
  name         = "main-backup-selection"
  plan_id      = aws_backup_plan.main.id

  selection_tag {
    type  = "STRINGEQUALS"
    key   = "Backup"
    value = "true"
  }
}

resource "aws_iam_role" "backup" {
  name = "backup-role-${random_id.bucket_suffix.hex}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "backup.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "backup" {
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSBackupServiceRolePolicyForBackup"
  role       = aws_iam_role.backup.name
}

resource "aws_dynamodb_table" "backup_index" {
  name         = "backup-metadata-${random_id.bucket_suffix.hex}"
  billing_mode = "PAY_PER_REQUEST"
  hash_key     = "backup_id"

  attribute {
    name = "backup_id"
    type = "S"
  }

  point_in_time_recovery {
    enabled = true
  }

  server_side_encryption {
    enabled = true
  }
}

provider "aws" {
  alias  = "west"
  region = "us-west-2"
}
```

